import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import Header from "../component/Header";

function LoggerScreen() {
  const navigate = useNavigate();
  const [dateFirst, setDateFirst] = useState("");
  const [dateSecound, setDateSecound] = useState("");
  const [dateThrid, setDateThrid] = useState("");
  useEffect(() => {
    setDatetime();
  }, []);
  const setDatetime = () => {
    const now = new Date();
    const format = (d) => {
      const y = d.getFullYear();
      const m = (d.getMonth() + 1).toString().padStart(2, "0");
      return `${y}-${m}`;
    };
    setDateFirst(format(now));

    // One Month Ago
    const d2 = new Date(now.getFullYear(), now.getMonth() - 1);
    setDateSecound(format(d2));

    // Two Months Ago
    const d3 = new Date(now.getFullYear(), now.getMonth() - 2);
    setDateThrid(format(d3));
  };
  const logger_list = (data) => {
    navigate("/logger_detail", {
      state: {
        filterDate: data,
      },
    });
  };
  return (
    <div className="container-fluid">
      <Header name={"Logger"} />
      <div
        className="container background-setting"
        onClick={() => logger_list(dateFirst)}
      >
        <div className="card mt-3">
          <div className="card-body">
            <div className="row">
              <div className="col-md-6 text-injection-setting  align-self-center fs-3">
                {dateFirst}
              </div>
              <div className="col-md-6 p-3">
                <div className="clearfix">
                  <div className="float-end">
                    <i className="fa fa-chevron-right fa-2x"></i>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div
        className="container background-setting mt-3"
        onClick={() => logger_list(dateSecound)}
      >
        <div className="card mt-3">
          <div className="card-body">
            <div className="row">
              <div className="col-md-6 text-injection-setting  align-self-center fs-3">
                {dateSecound}
              </div>
              <div className="col-md-6 p-3">
                <div className="clearfix">
                  <div className="float-end">
                    <i className="fa fa-chevron-right fa-2x"></i>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <div
        className="container background-setting mt-3"
        onClick={() => logger_list(dateThrid)}
      >
        <div className="card mt-3">
          <div className="card-body">
            <div className="row">
              <div className="col-md-6 text-injection-setting  align-self-center fs-3">
                {dateThrid}
              </div>
              <div className="col-md-6 p-3">
                <div className="clearfix">
                  <div className="float-end">
                    <i className="fa fa-chevron-right fa-2x"></i>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default LoggerScreen;
