import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import Header from "../component/Header";
import { API_PATHS } from "../component/PathApi";

function Setting() {
  const navigate = useNavigate();
  const modalRef = useRef();
  const modalUpdate = useRef();
  const modalInstance = useRef();
  const modalLoading = useRef();
  const [statusError, serStatusError] = useState(false);
  const [userName, setUserName] = useState("");
  const [Password, setPassword] = useState("");
  const [clickPage, setClickPage] = useState("");
  useEffect(() => {
    modalInstance.current = new Modal(modalRef.current);
    modalLoading.current = new Modal(modalUpdate.current);
  }, []);

  const showModal = (page) => {
    setClickPage(page);
    modalInstance.current.show();
  };
  const hideModal = () => modalInstance.current.hide();
  const hideModalLoading = () => modalLoading.current.hide();
  const checkPermisstion = () => {
    if (userName === "administrator" && Password === "12345") {
      if (clickPage === "machine_option") {
        navigate("/machine_option");
      }
      if (clickPage === "online_setting") {
        navigate("/online_setting");
      }
      if (clickPage === "update_version") {
        confirmUpdateCode();
        modalLoading.current.show();
      }

      hideModal();
    } else {
      serStatusError(true);
    }
  };
  const changeName = (e) => {
    setUserName(e);
    serStatusError(false);
  };
  const changePwd = (e) => {
    setPassword(e);
    serStatusError(false);
  };
  const confirmUpdateCode = () => {
    fetch(API_PATHS.path_update_version, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({}),
    });
  };

  return (
    <div className="container-fluid">
      <Header name={"Setting"} />
      <div className="mt-3">
        <div className="card" onClick={() => showModal("machine_option")}>
          <div className="card-body font-size-middle">
            <div className="d-flex justify-content-between">
              <div>Machine Option</div>
              <div>
                <i className="fa fa-chevron-right fa-lg"></i>
              </div>
            </div>
          </div>
        </div>
      </div>
      <div className="mt-3">
        <div className="card" onClick={() => showModal("online_setting")}>
          <div className="card-body font-size-middle">
            <div className="d-flex justify-content-between">
              <div>Online Setting</div>
              <div>
                <i className="fa fa-chevron-right fa-lg"></i>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="mt-3">
        <div className="card" onClick={() => showModal("update_version")}>
          <div className="card-body font-size-middle">
            <div className="d-flex justify-content-between">
              <div>Update Version</div>
              <div>
                <i className="fa fa-chevron-right fa-lg"></i>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="modal fade" ref={modalRef} tabIndex="-1">
        <div className="modal-dialog">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Permission</h5>
              <button
                type="button"
                className="btn-close"
                onClick={hideModal}
              ></button>
            </div>
            <div className="modal-body">
              <div
                className={`alert alert-danger ${statusError ? "" : "d-none"}`}
              >
                <strong>Error!</strong> Your information is incorrect.
              </div>
              <div className="form-group">
                <label>User Name :</label>
                <input
                  type="text"
                  className="form-control"
                  value={userName}
                  onChange={(e) => changeName(e.target.value)}
                ></input>
              </div>

              <div className="form-group">
                <label>Password :</label>
                <input
                  type="password"
                  className="form-control"
                  value={Password}
                  onChange={(e) => changePwd(e.target.value)}
                ></input>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={hideModal}>
                Close
              </button>
              <button className="btn btn-primary" onClick={checkPermisstion}>
                Confirm
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="modal fade" ref={modalUpdate} tabIndex="-1">
        <div className="modal-dialog">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">LOADING</h5>
              <button
                type="button"
                className="btn-close"
                onClick={hideModalLoading}
              ></button>
            </div>
            <div className="modal-body">
              <div className="text-center">
                <div className="spinner-grow text-muted"></div>
                <div className="spinner-grow text-primary"></div>
                <div className="spinner-grow text-success"></div>
                <div className="spinner-grow text-info"></div>
                <div className="spinner-grow text-warning"></div>
                <div className="spinner-grow text-danger"></div>
                <div className="spinner-grow text-secondary"></div>
                <div className="spinner-grow text-dark"></div>
                <div className="spinner-grow text-light"></div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={hideModalLoading}>
                Close
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Setting;
