import { API_PATHS } from "../component/PathApi";
export class ServerUpdate {
  static async online_update() {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      if (parseInt(data.online_mode) === 1) {
        return data.machine_code;
      } else {
        return false;
      }
    }
  }
  static async update_table(table, field, value) {
    const machineCode = await this.online_update();
    if (machineCode !== false) {
      fetch(API_PATHS.path_online_update_table, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          machineCode: machineCode,
          tableSet: table,
          fieldSet: field,
          valueSet: value,
        }),
      });
    }
  }
  static async update_online_pump(table, field, value, id) {
    const machineCode = await this.online_update();
    if (machineCode !== false) {
      fetch(API_PATHS.path_online_update_pump, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          machineCode: machineCode,
          tableSet: table,
          fieldSet: field,
          valueSet: value,
          filtrationID: id,
        }),
      });
    }
  }
  static async update_online_injection(table, field, value, id) {
    const machineCode = await this.online_update();
    if (machineCode !== false) {
      fetch(API_PATHS.path_online_update_injection, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          machineCode: machineCode,
          tableSet: table,
          fieldSet: field,
          valueSet: value,
          filtrationID: id,
        }),
      });
    }
  }
  static async update_online_injection_week(table, field, value, id) {
    const machineCode = await this.online_update();
    if (machineCode !== false) {
      fetch(API_PATHS.path_online_update_injection_week, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          machineCode: machineCode,
          tableSet: table,
          fieldSet: field,
          valueSet: value,
          filtrationID: id,
        }),
      });
    }
  }
}
