import { useEffect, useState, useRef } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import Swal from "sweetalert2";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function AdvanceScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [startPump, setStartPump] = useState(0);
  const [stopPump, setStopPump] = useState(0);
  const [tempDiff, setTempDiff] = useState(0);
  const [pressureLow, setPressureLow] = useState(0);
  const [pressureHigh, setPressureHigh] = useState(0);
  const [counterPressure, setCounterPressure] = useState(0);
  const [lockMachine, setLockMachine] = useState(0);
  const [typeCalibrate, setTypeCalibrate] = useState(0);
  const [calibrateTotal, setCalibrateTotal] = useState(0);
  const [bypassPressure, setBypassPressure] = useState(0);
  const [pressureMode, setPressureMode] = useState(false);
  const [datetime, setDatetime] = useState("");
  const [vfdFiltration, setVfdFiltration] = useState(0);
  const [vfdBackwash, setVfdBackwash] = useState(0);
  const [vfdOption, setVfdOption] = useState(false);
  useEffect(() => {
    fetchAdvance();
    fetchFunctionMode();
    fetchSetting();
    fetchMachineOption();
  }, []);
  const fetchMachineOption = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      const status_vfd = parseInt(data.vfd) === 0 ? false : true;
      setVfdOption(status_vfd);
    }
  };
  const fetchSetting = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      if (parseInt(data.pressure) === 1) {
        setPressureMode(true);
      } else {
        setPressureMode(false);
      }
    }
  };
  const fetchFunctionMode = async () => {
    const response = await fetch(API_PATHS.path_mode);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setBypassPressure(data.fm_bypass_pressure);
    }
  };
  const fetchAdvance = async () => {
    const response = await fetch(API_PATHS.path_advance);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setStartPump(data.start_pump);
      setStopPump(data.stop_pump);
      setTempDiff(data.temperature_diff);
      setPressureLow(data.low_pressure);
      setPressureHigh(data.max_pressure);
      setCounterPressure(data.countdown_pressure);
      setLockMachine(data.lock_machine);
      setTypeCalibrate(changeIntToBoolean(data.pressure_calibrate_type));
      setCalibrateTotal(data.pressure_calibrate_total);
      setVfdFiltration(data.vfd_filtration);
      setVfdBackwash(data.vfd_backwash);

      const now = new Date();
      const year = now.getFullYear(); // 2025
      const month = now.getMonth() + 1; // 10 (January is 0, November is 10)
      const dayOfMonth = now.getDate();
      const hours = now.getHours(); // 9
      const minutes = now.getMinutes(); // 13
      const seconds = now.getSeconds(); // 0
      var new_month = addingNumberString(month);
      var new_day = addingNumberString(dayOfMonth);
      var new_hour = addingNumberString(hours);
      var new_minute = addingNumberString(minutes);
      var new_sec = addingNumberString(seconds);
      const txt_time =
        year +
        "-" +
        new_month +
        "-" +
        new_day +
        " " +
        new_hour +
        ":" +
        new_minute +
        ":" +
        new_sec;
      setDatetime(txt_time);
    }
  };
  const addingNumberString = (value) => {
    if (parseInt(value) < 10) {
      return "0" + value.toString();
    } else {
      return value.toString();
    }
  };
  const changeIntToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const addNumber = (field, value, type) => {
    var new_value = 0;
    if (field === "start_pump") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 10) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setStartPump(new_value);
    } else if (field === "stop_pump") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 59) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setStopPump(new_value);
    } else if (field === "temperature_diff") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 10) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setTempDiff(new_value);
    } else if (field === "countdown_pressure") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 30) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setCounterPressure(new_value);
    } else if (field === "lock_machine") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 5) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setLockMachine(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const addDecimal = (field, value, type) => {
    var new_value = 0.0;
    if (field === "low_pressure") {
      new_value = parseFloat(value);
      if (type === "plus") {
        if (new_value < 2) {
          new_value += 0.1;
        }
      } else {
        if (new_value > 0.1) {
          new_value -= 0.1;
        }
      }
      setPressureLow(new_value.toFixed(1));
    } else if (field === "max_pressure") {
      new_value = parseFloat(value);
      if (type === "plus") {
        if (new_value < 3) {
          new_value += 0.1;
        }
      } else {
        if (new_value > 0.1) {
          new_value -= 0.1;
        }
      }
      setPressureHigh(new_value.toFixed(1));
    }
    fetchUpdate(field, new_value.toFixed(1));
  };
  const addDecimal2 = (field, value, type) => {
    var new_value = 0.0;
    if (field === "pressure_calibrate_total") {
      new_value = parseFloat(value);
      if (type === "plus") {
        new_value += 0.01;
      } else {
        if (new_value > 0) {
          new_value -= 0.01;
        }
      }
      setCalibrateTotal(new_value.toFixed(2));
    }
    fetchUpdate(field, new_value.toFixed(2));
  };
  const changeModeCalibrate = () => {
    var new_status = !typeCalibrate;
    setTypeCalibrate(new_status);
    fetchUpdate("pressure_calibrate_type", new_status ? 1 : 0);
  };
  const addVFD = (field, value, type) => {
    var new_value = parseInt(value);
    if (field === "vfd_filtration") {
      if (type === "plus") {
        if (new_value < 100) {
          new_value = new_value + 5;
        }
      } else {
        if (new_value > 5) {
          new_value = new_value - 5;
        }
      }
      setVfdFiltration(new_value);
    } else if (field === "vfd_backwash") {
      if (type === "plus") {
        if (new_value < 100) {
          new_value = new_value + 5;
        }
      } else {
        if (new_value > 5) {
          new_value = new_value - 5;
        }
      }
      setVfdBackwash(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };
  const changeModeByPass = (value) => {
    setBypassPressure(value);
    updateFunctionMode("fm_bypass_pressure", value);
  };

  const updateFunctionMode = (field, value) => {
    fetch(API_PATHS.path_mode, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_mode", field, value);
  };
  const setMachineDate = () => {
    fetch(API_PATHS.path_set_time, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        date_time: datetime,
      }),
    })
      .then((response) => response.json())
      .then((data) => {
        if (data.status === 200) {
          Swal.fire({
            position: "top-end",
            icon: "success",
            title: "Your work has been saved",
            showConfirmButton: false,
            timer: 1500,
          });
        }
      });
  };
  return (
    <div className="container-fluid">
      <Header
        name={`${
          language === "fr"
            ? fr_lang.start_delay_settings
            : en_lang.start_delay_settings
        }`}
      />
      <div
        className={`box-glass p-2 h-100 mt-3 ${pressureMode ? "" : "d-none"}`}
      >
        <div className="box-container-header ">
          {language === "fr"
            ? fr_lang.pressure_control
            : en_lang.pressure_control}
        </div>
        <div className="switch-toggle switch-3 switch-candy mt-3">
          <input
            id="menu_on"
            name="menu_mode"
            type="radio"
            checked={bypassPressure === 1}
            onChange={() => changeModeByPass(1)}
          />
          <label htmlFor="menu_on">
            {language === "fr" ? fr_lang.open : en_lang.open}
          </label>
          <input
            id="menu_off"
            name="menu_mode"
            type="radio"
            checked={bypassPressure === 0}
            onChange={() => changeModeByPass(0)}
          />
          <label htmlFor="menu_off">
            {language === "fr" ? fr_lang.close : en_lang.close}
          </label>
          <a href=""></a>
        </div>
      </div>

      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr"
            ? fr_lang.advanced_settings
            : en_lang.advanced_settings}
        </div>
        <div className="row ">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_pump_start_up_time
              : en_lang.water_pump_start_up_time}{" "}
            [ 1 - 10 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addNumber("start_pump", startPump, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {startPump}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addNumber("start_pump", startPump, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_pump_shut_off_time
              : en_lang.water_pump_shut_off_time}{" "}
            [ 1 - 59 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addNumber("stop_pump", stopPump, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {stopPump}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addNumber("stop_pump", stopPump, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            {language === "fr"
              ? fr_lang.differential_cutoff_temperature
              : en_lang.differential_cutoff_temperature}{" "}
            [ 1 - 10 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addNumber("temperature_diff", tempDiff, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {tempDiff}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addNumber("temperature_diff", tempDiff, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7 font-size-small align-self-center content-color">
            {language === "fr"
              ? fr_lang.low_pressure_differential
              : en_lang.low_pressure_differential}{" "}
            [ 0 - 2 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addDecimal("low_pressure", pressureLow, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {pressureLow}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addDecimal("low_pressure", pressureLow, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            {language === "fr"
              ? fr_lang.high_pressure_cutoff
              : en_lang.high_pressure_cutoff}{" "}
            [ 0 - 3 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addDecimal("max_pressure", pressureHigh, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {pressureHigh}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addDecimal("max_pressure", pressureHigh, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            {language === "fr"
              ? fr_lang.pressure_recovery_time
              : en_lang.pressure_recovery_time}{" "}
            [ 1 - 30 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addNumber("countdown_pressure", counterPressure, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {counterPressure}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addNumber("countdown_pressure", counterPressure, "plus")
                }
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small align-self-center content-color">
            {language === "fr"
              ? fr_lang.frequency_of_blood_pressure_restoration
              : en_lang.frequency_of_blood_pressure_restoration}{" "}
            [ 1 - 5 ]
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addNumber("lock_machine", lockMachine, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {lockMachine}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addNumber("lock_machine", lockMachine, "plus")}
              ></i>
            </div>
          </div>
        </div>
      </div>

      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">Calibrate pression</div>
        <div className="row mt-2">
          <div className="col-md-6  font-size-small  align-self-center content-color">
            Type
          </div>
          <div className="col-md-6 ">
            <div className="clearfix">
              <div className="float-end">
                <div className="switch-toggle-small">
                  <input
                    className="switch-toggle-checkbox"
                    type="checkbox"
                    checked={typeCalibrate || false}
                    onChange={() => changeModeCalibrate()}
                  />
                  <label
                    className="switch-toggle-label"
                    htmlFor="pricing-plan-switch"
                  >
                    <span>MINUS</span>
                    <span>PLUS</span>
                  </label>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            Calibrate
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addDecimal2(
                    "pressure_calibrate_total",
                    calibrateTotal,
                    "minus",
                  )
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {calibrateTotal}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addDecimal2(
                    "pressure_calibrate_total",
                    calibrateTotal,
                    "plus",
                  )
                }
              ></i>
            </div>
          </div>
        </div>
      </div>

      <div className={`box-glass p-2 h-100 mt-3 ${vfdOption ? "" : "d-none"}`}>
        <div className="box-container-header ">VFD</div>
        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            Filtration
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addVFD("vfd_filtration", vfdFiltration, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {vfdFiltration}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addVFD("vfd_filtration", vfdFiltration, "plus")}
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-7  font-size-small  align-self-center content-color">
            Backwash
          </div>
          <div className="col-md-5 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addVFD("vfd_backwash", vfdBackwash, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">
                {vfdBackwash}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addVFD("vfd_backwash", vfdBackwash, "plus")}
              ></i>
            </div>
          </div>
        </div>
      </div>

      <div className="box-glass p-2 h-100 mt-3 mb-3">
        <div className="box-container-header ">
          {language === "fr"
            ? fr_lang.setting_machine_time
            : en_lang.setting_machine_time}
        </div>
        <div className="row mt-2">
          <div className="col-md-6  font-size-small  align-self-center content-color">
            Setting
          </div>
          <div className="col-md-6 ">
            <input
              type="datetime-local"
              className="form-control"
              value={datetime}
              onChange={(e) => setDatetime(e.target.value)}
            />
          </div>
          <div className="col-md-12 mt-2">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => setMachineDate()}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default AdvanceScreen;
