import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { ServerUpdate } from "../component/ServerUpdate";
function MachineOption() {
  const [heater_1, setHeater_1] = useState(false);
  const [heater_2, setHeater_2] = useState(false);
  const [pressure, setPressure] = useState(false);
  const [pH, setPH] = useState(false);
  const [orp, setOrp] = useState(false);
  const [chlorine, setChlorine] = useState(false);
  const [chlorineWeek, setChlorineWeek] = useState(false);
  const [aco, setAco] = useState(false);
  const [oxyGen, setOxyGen] = useState(false);
  const [oxyGenWeek, setOxyGenWeek] = useState(false);
  const [apf, setApf] = useState(false);
  const [apfWeek, setApfWeek] = useState(false);
  const [ozonePump, setOzonePump] = useState(false);
  const [uvLamp, setUVLamp] = useState(false);
  const [ozoneLamp, setOzoneLamp] = useState(false);
  const [pump, setPump] = useState(false);
  const [tank1, setTank1] = useState(false);
  const [tank2, setTank2] = useState(false);
  const [pool, setPool] = useState(false);
  const [backWash, setBackWash] = useState(false);
  const [heatPumpHeat, setHeatPumpHeat] = useState(false);
  const [heatPumpCool, setHeatPumpCool] = useState(false);
  const [flowSensor, setFlowSensor] = useState(false);
  const [uvAmalgam, setUvAmalgam] = useState(false);
  const [nightTime, setNightTime] = useState(false);
  const [vfd, setVfd] = useState(false);
  useEffect(() => {
    fetchSetting();
  });
  const fetchSetting = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      setHeater_1(changeNumberToBoolean(data.heater_1));
      setHeater_2(changeNumberToBoolean(data.heater_2));
      setPressure(changeNumberToBoolean(data.pressure));
      setPH(changeNumberToBoolean(data.ph));
      setOrp(changeNumberToBoolean(data.orp));
      setAco(changeNumberToBoolean(data.aco));
      setOxyGen(changeNumberToBoolean(data.oxygen));
      setOxyGenWeek(changeNumberToBoolean(data.oxygen_week));
      setApf(changeNumberToBoolean(data.apf));
      setApfWeek(changeNumberToBoolean(data.apf_week));
      setOzonePump(changeNumberToBoolean(data.ozone_pump));
      setUVLamp(changeNumberToBoolean(data.uv_lamp));
      setOzoneLamp(changeNumberToBoolean(data.ozone_lamp));
      setPump(changeNumberToBoolean(data.pump));
      setChlorine(changeNumberToBoolean(data.chlorine));
      setChlorineWeek(changeNumberToBoolean(data.chlorine_week));
      setPool(changeNumberToBoolean(data.pool));
      setBackWash(changeNumberToBoolean(data.backwash));
      setHeatPumpHeat(changeNumberToBoolean(data.heatpump_heating));
      setHeatPumpCool(changeNumberToBoolean(data.heatpump_cooling));
      setFlowSensor(changeNumberToBoolean(data.flow_sensor));
      setUvAmalgam(changeNumberToBoolean(data.uv_amalgam));
      setNightTime(changeNumberToBoolean(data.night_time));
      setVfd(changeNumberToBoolean(data.vfd));
      setTank1(data.tank_1);
      setTank2(data.tank_2);
    }
  };
  const changeNumberToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const changeSetting = (mode) => {
    var new_value = false;
    if (mode === "heater_1") {
      new_value = !heater_1;
      setHeater_1(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setPool(false);
        fetchUpdate("pool", 0);
        setUvAmalgam(false);
        fetchUpdate("uv_amalgam", 0);
      } else {
        fetchUpdateAdvance("winter_mode_active", 0);
      }
    } else if (mode === "heater_2") {
      new_value = !heater_2;
      setHeater_2(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setPump(false);
        fetchUpdate("pump", 0);
        setOzonePump(false);
        fetchUpdate("ozone_pump", 0);
        setPool(false);
        fetchUpdate("pool", 0);
      }
    } else if (mode === "pressure") {
      new_value = !pressure;
      setPressure(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "ph") {
      new_value = !pH;
      setPH(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setApf(false);
        fetchUpdate("apf", 0);
        setApfWeek(false);
        fetchUpdate("apf_week", 0);
      }
    } else if (mode === "orp") {
      new_value = !orp;
      setOrp(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setChlorine(false);
        fetchUpdate("chlorine", 0);
        setAco(false);
        fetchUpdate("aco", 0);
        setChlorineWeek(false);
        fetchUpdate("chlorine_week", 0);
      }
    } else if (mode === "aco") {
      new_value = !aco;
      setAco(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setChlorine(false);
        fetchUpdate("chlorine", 0);
        setOrp(false);
        fetchUpdate("orp", 0);
        setChlorineWeek(false);
        fetchUpdate("chlorine_week", 0);
      }
    } else if (mode === "oxygen") {
      new_value = !oxyGen;
      setOxyGen(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setOxyGenWeek(false);
        fetchUpdate("oxygen_week", 0);
      }
    } else if (mode === "oxygen_week") {
      new_value = !oxyGenWeek;
      setOxyGenWeek(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setOxyGen(false);
        fetchUpdate("oxygen", 0);
      }
    } else if (mode === "apf") {
      new_value = !apf;
      setApf(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setPH(false);
        fetchUpdate("ph", 0);
        setApfWeek(false);
        fetchUpdate("apf_week", 0);
      }
    } else if (mode === "apf_week") {
      new_value = !apfWeek;
      setApfWeek(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setPH(false);
        fetchUpdate("ph", 0);
        setApf(false);
        fetchUpdate("apf", 0);
      }
    } else if (mode === "ozone_pump") {
      new_value = !ozonePump;
      setOzonePump(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setHeater_2(false);
        fetchUpdate("heater_2", 0);
        setPump(false);
        fetchUpdate("pump", 0);
      }
    } else if (mode === "uv_lamp") {
      new_value = !uvLamp;
      setUVLamp(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "ozone_lamp") {
      new_value = !ozoneLamp;
      setOzoneLamp(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "pump") {
      new_value = !pump;
      setPump(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value) {
        setHeater_2(false);
        fetchUpdate("heater_2", 0);
        setOzonePump(false);
        fetchUpdate("ozone_pump", 0);
      }
    } else if (mode === "chlorine") {
      new_value = !chlorine;
      setChlorine(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setAco(false);
        fetchUpdate("aco", 0);
        setOrp(false);
        fetchUpdate("orp", 0);
        setChlorineWeek(false);
        fetchUpdate("chlorine_week", 0);
      }
    } else if (mode === "chlorine_week") {
      new_value = !chlorineWeek;
      setChlorineWeek(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setAco(false);
        fetchUpdate("aco", 0);
        setOrp(false);
        fetchUpdate("orp", 0);
        setChlorine(false);
        fetchUpdate("chlorine", 0);
      }
    } else if (mode === "pool") {
      new_value = !pool;
      setPool(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setHeater_1(false);
        fetchUpdate("heater_1", 0);
        setHeater_2(false);
        fetchUpdate("heater_2", 0);
        fetchUpdateAdvance("winter_mode_active", 0);
      }
    } else if (mode === "backwash") {
      new_value = !backWash;
      setBackWash(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "heatpump_heating") {
      new_value = !heatPumpHeat;
      setHeatPumpHeat(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value) {
        setHeatPumpCool(false);
        fetchUpdate("heatpump_cooling", 0);
      }
    } else if (mode === "heatpump_cooling") {
      new_value = !heatPumpCool;
      setHeatPumpCool(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value) {
        setHeatPumpHeat(false);
        fetchUpdate("heatpump_heating", 0);
      }
    } else if (mode === "flow_sensor") {
      new_value = !flowSensor;
      setFlowSensor(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "uv_amalgam") {
      new_value = !uvAmalgam;
      setUvAmalgam(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
      if (new_value === true) {
        setHeater_1(false);
        fetchUpdate("heater_1", 0);
      }
    } else if (mode === "night_time") {
      new_value = !nightTime;
      setNightTime(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    } else if (mode === "vfd") {
      new_value = !vfd;
      setVfd(new_value);
      fetchUpdate(mode, new_value ? 1 : 0);
    }
  };
  const setTank1Injection = (tank, value) => {
    if (tank === "tank1") {
      if (value === tank1) {
        setTank1("None");
        fetchUpdate("tank_1", "None");
      } else {
        setTank1(value);
        fetchUpdate("tank_1", value);
      }
    }
    if (tank === "tank2") {
      if (value === tank2) {
        setTank2("None");
        fetchUpdate("tank_2", "None");
      } else {
        setTank2(value);
        fetchUpdate("tank_2", value);
      }
    }
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_machine_option, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("machine_option", field, value);
  };
  const fetchUpdateAdvance = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };
  return (
    <div className="container-fluid">
      <Header name={"Machine Option"} />
      <div className="box-glass p-2 h-100 mt-3 mb-3">
        <div className="box-container-header ">Machine Option</div>
        <div className="row">
          <div className="col-6">
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Heater
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={heater_1}
                onChange={() => changeSetting("heater_1")}
              />{" "}
              Heater 1
            </div>
            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={heater_2}
                onChange={() => changeSetting("heater_2")}
              />{" "}
              Heater 2
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Heat Pump
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={heatPumpHeat}
                onChange={() => changeSetting("heatpump_heating")}
              />{" "}
              Heating
            </div>
            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={heatPumpCool}
                onChange={() => changeSetting("heatpump_cooling")}
              />{" "}
              Cooling
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Backwash
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={backWash}
                onChange={() => changeSetting("backwash")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> pH
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={pH}
                onChange={() => changeSetting("ph")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> APF
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={apf}
                onChange={() => changeSetting("apf")}
              />
              APF (original)
            </div>
            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={apfWeek}
                onChange={() => changeSetting("apf_week")}
              />
              APF (Week)
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> ORP
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={orp}
                onChange={() => changeSetting("orp")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Chlorine
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={chlorine}
                onChange={() => changeSetting("chlorine")}
              />{" "}
              Chlorine (Original)
            </div>
            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={chlorineWeek}
                onChange={() => changeSetting("chlorine_week")}
              />{" "}
              Chlorine (Week)
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> ACO
            </div>

            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={aco}
                onChange={() => changeSetting("aco")}
              />{" "}
              ACO (Week)
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Oxygen
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={oxyGen}
                onChange={() => changeSetting("oxygen")}
              />
              Oxigen (Original)
            </div>
            <div className="form-check form-switch ms-2 mt-2 ">
              <input
                className="form-check-input"
                type="checkbox"
                checked={oxyGenWeek}
                onChange={() => changeSetting("oxygen_week")}
              />
              Oxigen (Week)
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Flow Sensor
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={flowSensor}
                onChange={() => changeSetting("flow_sensor")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Night Time
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={nightTime}
                onChange={() => changeSetting("night_time")}
              />
            </div>

            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> VFD
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={vfd}
                onChange={() => changeSetting("vfd")}
              />
            </div>
          </div>
          <div className="col-6">
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Pressure
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={pressure}
                onChange={() => changeSetting("pressure")}
              />
            </div>

            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> UV Lamp
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={uvLamp}
                onChange={() => changeSetting("uv_lamp")}
              />{" "}
              UV 1
            </div>
            <div className="form-check form-switch ms-2 mt-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={uvAmalgam}
                onChange={() => changeSetting("uv_amalgam")}
              />{" "}
              UV 2
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Ozone Lamp
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={ozoneLamp}
                onChange={() => changeSetting("ozone_lamp")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Ozone Pump
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={ozonePump}
                onChange={() => changeSetting("ozone_pump")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Pump 2
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={pump}
                onChange={() => changeSetting("pump")}
              />
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i>Sensor Tank 1
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "ph"}
                onChange={() => setTank1Injection("tank1", "ph")}
              />{" "}
              pH
            </div>
            <div className="form-check form-switch mt-2  ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "orp"}
                onChange={() => setTank1Injection("tank1", "orp")}
              />{" "}
              ORP
            </div>
            <div className="form-check form-switch  mt-2 ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "apf"}
                onChange={() => setTank1Injection("tank1", "apf")}
              />{" "}
              APF
            </div>
            <div className="form-check form-switch mt-2  ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "chlorine"}
                onChange={() => setTank1Injection("tank1", "chlorine")}
              />{" "}
              Chlorine
            </div>
            <div className="form-check form-switch mt-2  ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "aco"}
                onChange={() => setTank1Injection("tank1", "aco")}
              />{" "}
              ACO
            </div>
            <div className="form-check form-switch mt-2 ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank1 === "oxygen"}
                onChange={() => setTank1Injection("tank1", "oxygen")}
              />{" "}
              Oxygen
            </div>
            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Sensor Tank 2
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "ph"}
                onChange={() => setTank1Injection("tank2", "ph")}
              />{" "}
              pH
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "orp"}
                onChange={() => setTank1Injection("tank2", "orp")}
              />{" "}
              ORP
            </div>
            <div className="form-check form-switch  mt-2 ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "apf"}
                onChange={() => setTank1Injection("tank2", "apf")}
              />{" "}
              APF
            </div>
            <div className="form-check form-switch mt-2  ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "chlorine"}
                onChange={() => setTank1Injection("tank2", "chlorine")}
              />{" "}
              Chlorine
            </div>
            <div className="form-check form-switch mt-2  ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "aco"}
                onChange={() => setTank1Injection("tank2", "aco")}
              />{" "}
              ACO
            </div>
            <div className="form-check form-switch mt-2 ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={tank2 === "oxygen"}
                onChange={() => setTank1Injection("tank2", "oxygen")}
              />{" "}
              Oxygen
            </div>

            <div className="font-size-middle">
              <i className="fa fa-caret-right"></i> Pool
            </div>
            <div className="form-check form-switch ms-2">
              <input
                className="form-check-input"
                type="checkbox"
                checked={pool}
                onChange={() => changeSetting("pool")}
              />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default MachineOption;
