import { useEffect, useState, useRef } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import Swal from "sweetalert2";
function OnlineSetting() {
  const [onlineMode, setOnlineMode] = useState(0);
  const [machineCode, setMachineCode] = useState("");
  useEffect(() => {
    const fetchSetting = async () => {
      const response = await fetch(API_PATHS.path_machine_option);
      const result = await response.json();
      if (result.status === 200) {
        const data = result.data.machine_option[0];
        setMachineCode(data.machine_code);
        setOnlineMode(parseInt(data.online_mode));
      }
    };
    fetchSetting();
  }, []);

  const OnlineMode = async (mode) => {
    const numericMode = parseInt(mode); // Convert once
    setOnlineMode(numericMode);
    if (mode === 1) {
      const response = await fetch(API_PATHS.path_online);
      const result = await response.json();
      if (result.status === 200) {
        fetchOnline(result.data, mode);
      }
    } else {
      updateMachineOption("machine_code", machineCode);
      updateMachineOption("online_mode", mode);
      Swal.fire({
        position: "top-end",
        icon: "success",
        title: "Your work has been saved",
        showConfirmButton: false,
        timer: 1500,
      });
    }
  };
  const updateMachineOption = async (field, value) => {
    fetch(API_PATHS.path_machine_option, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
  };
  const fetchOnline = async (data) => {
    const now = new Date();
    const year = now.getFullYear(); // 2025
    const month = now.getMonth() + 1; // 10 (January is 0, November is 10)
    const dayOfMonth = now.getDate();
    const hours = now.getHours(); // 9
    const minutes = now.getMinutes(); // 13
    const seconds = now.getSeconds(); // 0
    const txt_time =
      dayOfMonth +
      "-" +
      month +
      "-" +
      year +
      " " +
      hours +
      ":" +
      minutes +
      ":" +
      seconds;
    fetch(API_PATHS.path_online_setting, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },

      body: JSON.stringify({
        machineCode: machineCode,
        advance: data.advance[0],
        backwash: data.backwash[0],
        hour: data.hour,
        injection: data.injection,
        injection_week: data.injection_week,
        machine_option: data.machine_option[0],
        mode: data.mode[0],
        dashboard: data.dashboard,
        machineTime: txt_time,
      }),
    })
      .then((response) => response.json())
      .then((data) => {
        if (data.status.code === 200) {
          setTimeout(() => {
            updateMachineOption("machine_code", machineCode);
            updateMachineOption("online_mode", 1);
            Swal.fire({
              position: "top-end",
              icon: "success",
              title: "Your work has been saved",
              showConfirmButton: false,
              timer: 1500,
            });
          }, 2000); // 2000 ms = 2 วินาที
        }
      });
  };
  return (
    <div className="container-fluid">
      <Header name={"Online Setting"} />
      <div className="form-group mt-3">
        <label className="fs-3 fw-bold">Machine Code</label>
        <input
          type="text"
          className="input-code-online"
          onChange={(e) => setMachineCode(e.target.value)}
          value={machineCode}
        />
      </div>

      <label className="fs-3 fw-bold mt-3">Online Setting</label>
      <div className="d-flex mt-2 ">
        <div
          className={`p-2 flex-fill text-center container-switch-left fw-bold ${onlineMode === 1 ? "bg-active" : "bg-unactive"}`}
          onClick={() => OnlineMode(1)}
        >
          Online
        </div>
        <div
          className={`p-2 flex-fill text-center container-switch-right fw-bold ${onlineMode === 0 ? "bg-active" : "bg-unactive"}`}
          onClick={() => OnlineMode(0)}
        >
          Offline
        </div>
      </div>
    </div>
  );
}
export default OnlineSetting;
