import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function HeaterScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [temperature, setTemperature] = useState(35);
  const [typeCalibrate, setTypeCalibrate] = useState(false);
  const [heaterActive, setHeaterActive] = useState(false);
  const [calibrateTotal, setCalibrateTotal] = useState(0);
  const [realTimeTemp, setRealTimeTemp] = useState("");
  useEffect(() => {
    fetchAdvance();
    fetchDashboard();
    const interval = setInterval(fetchDashboard, 3000);
    return () => clearInterval(interval);
  }, []);
  const fetchDashboard = async () => {
    const response = await fetch(API_PATHS.path_dashboard);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data;
      setRealTimeTemp(data.temperature);
    }
  };
  const fetchAdvance = async () => {
    const response = await fetch(API_PATHS.path_advance);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setTemperature(data.heater_temperature);
      setTypeCalibrate(changeIntToBoolean(data.heater_calibrate_type));
      setHeaterActive(data.heater_mode);
      setCalibrateTotal(data.heater_calibrate_total);
    }
  };
  const changeIntToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const changeModeHeater = (value) => {
    setHeaterActive(value);
    fetchUpdate("heater_mode", value);
  };
  const changeModeCalibrate = () => {
    var new_status = !typeCalibrate;
    setTypeCalibrate(new_status);
    fetchUpdate("heater_calibrate_type", new_status ? 1 : 0);
  };
  const addingNumber = (field, value, type) => {
    var new_value = parseInt(value);
    if (type === "plus") {
      new_value += 1;
    } else {
      if (new_value > 1) {
        new_value -= 1;
      }
    }
    setTemperature(new_value);
    fetchUpdate(field, new_value);
  };
  const addDecimal = (field, value, type) => {
    var new_value = parseFloat(value);
    if (type === "plus") {
      new_value += 0.01;
    } else {
      if (new_value > 0) {
        new_value -= 0.01;
      }
    }
    setCalibrateTotal(new_value.toFixed(2));
    fetchUpdate(field, new_value.toFixed(2));
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };
  return (
    <div className="container-fluid">
      <Header name={`${language === "fr" ? fr_lang.heater : en_lang.heater}`} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.temperature : en_lang.temperature}
        </div>
        <div className="d-flex justify-content-between mt-3">
          <div className="text-dark font-size-middle">
            {language === "fr" ? fr_lang.temperature : en_lang.temperature} :
          </div>
          <div className="text-dark font-size-middle">{realTimeTemp}</div>
        </div>
      </div>
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.heater : en_lang.heater}
        </div>
        <div className="switch-toggle switch-3 switch-candy mt-3">
          <input
            id="menu_on"
            name="menu_mode"
            type="radio"
            checked={heaterActive === 1}
            onChange={() => changeModeHeater(1)}
          />
          <label htmlFor="menu_on">
            {language === "fr" ? fr_lang.activated : en_lang.activated}
          </label>
          <input
            id="menu_off"
            name="menu_mode"
            type="radio"
            checked={heaterActive === 0}
            onChange={() => changeModeHeater(0)}
          />
          <label htmlFor="menu_off">
            {language === "fr" ? fr_lang.disabled : en_lang.disabled}
          </label>
          <a href=""></a>
        </div>

        <div className="row mt-2">
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_temperature
              : en_lang.water_temperature}{" "}
            (Heating)
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addingNumber("heater_temperature", temperature, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {temperature}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addingNumber("heater_temperature", temperature, "plus")
                }
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            Type
          </div>
          <div className="col-md-6 ">
            <div className="clearfix">
              <div className="float-end">
                <div className="switch-toggle-small">
                  <input
                    className="switch-toggle-checkbox"
                    type="checkbox"
                    checked={typeCalibrate || false}
                    onChange={() => changeModeCalibrate()}
                  />
                  <label
                    className="switch-toggle-label"
                    htmlFor="pricing-plan-switch"
                  >
                    <span>MINUS</span>
                    <span>PLUS</span>
                  </label>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            Calibrate
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addDecimal("heater_calibrate_total", calibrateTotal, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {calibrateTotal}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addDecimal("heater_calibrate_total", calibrateTotal, "plus")
                }
              ></i>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default HeaterScreen;
