import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { Constante } from "../component/Constante";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function OrpScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [injection, setInjection] = useState([]);
  const [filtration, setFiltration] = useState([]);
  const [start, setStart] = useState(0);
  const [stop, setStop] = useState(0);
  const [inj, setInj] = useState(0);
  const [freq, setFreq] = useState(0);
  useEffect(() => {
    fetctInjection();
  }, []);
  const fetctInjection = async () => {
    const response = await fetch(API_PATHS.path_injection);
    const result = await response.json();
    const response_filtration = await fetch(API_PATHS.path_filtration);
    const result_filtration = await response_filtration.json();
    //machine_option
    const response_machine_option = await fetch(API_PATHS.path_machine_option);
    const result_machine_option = await response_machine_option.json();

    if (result.status === 200) {
      const data = result.data.dataInfo[1];
      const filtration_data = result_filtration.data.dataInfo[0];

      const machine_option = result_machine_option.data.machine_option[0];
      const pump_2 = result_filtration.data.dataInfo[4];
      var new_arr = [];
      var new_filtration = [];
      for (var i = 1; i <= 24; i++) {
        var fieldInject = "ip_" + i.toString();
        var fieldFiltration = "fp_" + i.toString();
        new_arr.push(changeIntToBoolean(data[fieldInject]));
        if (parseInt(machine_option.pump) === 0) {
          new_filtration.push(filtration_data[fieldFiltration]);
        } else {
          if (
            changeIntToBoolean(pump_2[fieldFiltration]) ||
            changeIntToBoolean(filtration_data[fieldFiltration])
          ) {
            new_filtration.push(true);
          } else {
            new_filtration.push(false);
          }
        }
      }
      setStart(data.ip_start);
      setStop(data.ip_stop);
      setInj(data.ip_inj);
      setFreq(data.ip_freq);
      setFiltration(new_filtration);
      setInjection(new_arr);
    }
  };
  const changeIntToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const changeModeFiltration = (index) => {
    const newArr = [...injection]; // 1. ก๊อปปี้ข้อมูลเดิมมาใส่ตัวแปรใหม่
    newArr[index] = !newArr[index]; // 2. แก้ไขเฉพาะตำแหน่งที่ต้องการ
    setInjection(newArr);
    var setField = "ip_" + (index + 1).toString();
    fetchUpdate(setField, newArr[index] ? 1 : 0);
  };
  const addingOneDecimal = (field, value, type) => {
    var new_value = 0.0;
    if (field === "ip_inj") {
      new_value = parseFloat(value);
      if (type === "plus") {
        new_value += 0.1;
      } else {
        if (new_value > 0.2) {
          new_value -= 0.1;
        }
      }
      setInj(new_value.toFixed(1));
    }
    fetchUpdate(field, new_value.toFixed(1));
  };
  const addingNumber = (field, value, type) => {
    var new_value = 0;
    if (field === "ip_freq") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value += 1;
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setFreq(new_value);
    } else if (field === "ip_start") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value += 1;
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setStart(new_value);
    } else if (field === "ip_stop") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value += 1;
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setStop(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_injection, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        table_set: "orp",
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_online_injection("injection_pump", field, value, 2);
  };

  return (
    <div className="container-fluid">
      <Header name={"ORP Injection"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">ORP</div>
        <ul className="nav nav-tabs mt-3" role="tablist">
          <li className="nav-item">
            <a className="nav-link active" data-bs-toggle="tab" href="#home">
              {language === "fr" ? fr_lang.hour : en_lang.hour}
            </a>
          </li>
          <li className="nav-item">
            <a className="nav-link" data-bs-toggle="tab" href="#menu1">
              {language === "fr" ? fr_lang.setting : en_lang.setting}
            </a>
          </li>
        </ul>
        <div className="tab-content">
          <div id="home" className="tab-pane active">
            <table className="table">
              <thead>
                <tr>
                  <th>{language === "fr" ? fr_lang.hour : en_lang.hour}</th>
                  <th className="text-end">Mode</th>
                </tr>
              </thead>
              <tbody>
                {Constante.hour_setting.map((item, index) => (
                  <tr key={index}>
                    <td>{item}</td>
                    <td>
                      <div
                        className={`clearfix ${filtration[index] ? "" : "d-none"}`}
                      >
                        <div className="float-end">
                          <label className="switch">
                            <input
                              type="checkbox"
                              checked={injection[index] || false}
                              onChange={() => changeModeFiltration(index)}
                            />
                            <span className="slider"></span>
                          </label>
                        </div>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div id="menu1" className="container tab-pane fade">
            <div className="row">
              <div className="col-md-6  font-size-middle  align-self-center content-color">
                {language === "fr"
                  ? fr_lang.start_the_injection
                  : en_lang.start_the_injection}
              </div>
              <div className="col-md-6 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() => addingNumber("ip_start", start, "minus")}
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {start}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() => addingNumber("ip_start", start, "plus")}
                  ></i>
                </div>
              </div>
            </div>

            <div className="row mt-2">
              <div className="col-md-6  font-size-middle  align-self-center content-color">
                {language === "fr"
                  ? fr_lang.stop_the_injection
                  : en_lang.stop_the_injection}
              </div>
              <div className="col-md-6 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() => addingNumber("ip_stop", stop, "minus")}
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {stop}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() => addingNumber("ip_stop", stop, "plus")}
                  ></i>
                </div>
              </div>
            </div>

            <div className="row mt-2">
              <div className="col-md-6  font-size-middle  align-self-center content-color">
                Inj.
              </div>
              <div className="col-md-6 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() => addingOneDecimal("ip_inj", inj, "minus")}
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {inj}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() => addingOneDecimal("ip_inj", inj, "plus")}
                  ></i>
                </div>
              </div>
            </div>

            <div className="row mt-2">
              <div className="col-md-6  font-size-middle  align-self-center content-color">
                Freq.
              </div>
              <div className="col-md-6 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() => addingNumber("ip_freq", freq, "minus")}
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {freq}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() => addingNumber("ip_freq", freq, "plus")}
                  ></i>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default OrpScreen;
