import { useLocation, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";

function LoggerDetailScreen() {
  const { state } = useLocation();
  const { filterDate } = state;
  const [indexPage, setIndexPage] = useState(1);
  const [dataList, setDataList] = useState([]);
  const navigate = useNavigate();
  const backScreen = () => {
    navigate("/");
  };
  useEffect(() => {
    loadingingLoging(indexPage);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const loadingingLoging = async (index) => {
    await fetch(API_PATHS.path_logger, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        month: filterDate,
        index: index,
      }),
    })
      .then((response) => response.json())
      .then((data) => {
        if (data.status === 200) {
          setDataList([]);
          setDataList(data.data);
        }
      });
  };
  const changePage = async (mode) => {
    let new_page = indexPage;
    if (mode === "prev") {
      if (new_page > 1) {
        new_page -= 1;
        setIndexPage(new_page);
      }
    } else {
      new_page += 1;
      setIndexPage(new_page);
    }
    loadingingLoging(new_page);
  };
  return (
    <div className="container-fluid">
      <Header name={"Logger"} />
      <div className="row mt-3">
        <div className="col-md-12">
          <div className="table-responsive">
            <table className="table">
              <thead>
                <tr className="text-center">
                  <th>Date</th>
                  <th>Temperature</th>
                  <th>ph</th>
                  <th>orp</th>
                  <th>pressure</th>
                  <th>ch_1</th>
                  <th>ch_2</th>
                  <th>ch_3</th>
                  <th>ch_4</th>
                  <th>ch_5</th>
                  <th>ch_6</th>
                  <th>ch_7</th>
                  <th>ch_8</th>
                  <th>in_1</th>
                  <th>in_2</th>
                  <th>in_3</th>
                  <th>ac_1</th>
                  <th>ac_2</th>
                  <th>ac_3</th>
                </tr>
              </thead>
              <tbody>
                {dataList.map((item) => (
                  <tr key={item.dl_id} className="text-center">
                    <td>
                      {item.date} {item.time}
                    </td>
                    <td>{item.temperature}</td>
                    <td>{item.ph}</td>
                    <td>{item.orp}</td>
                    <td>{item.pressure}</td>
                    <td>{item.ch_1}</td>
                    <td>{item.ch_2}</td>
                    <td>{item.ch_3}</td>
                    <td>{item.ch_4}</td>
                    <td>{item.ch_5}</td>
                    <td>{item.ch_6}</td>
                    <td>{item.ch_7}</td>
                    <td>{item.ch_8}</td>
                    <td>{item.in_1}</td>
                    <td>{item.in_2}</td>
                    <td>{item.in_3}</td>
                    <td>{item.ac_1}</td>
                    <td>{item.ac_2}</td>
                    <td>{item.ac_3}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
        <div className="col-md-12 mb-3">
          <div className="d-flex justify-content-between">
            <div className="p-2">
              <button
                className="btn btn-info text-white"
                onClick={() => changePage("prev")}
              >
                Previous
              </button>
            </div>
            <div className="p-2">
              <button
                className="btn btn-info text-white"
                onClick={() => changePage("next")}
              >
                Next
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default LoggerDetailScreen;
