import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { Constante } from "../component/Constante";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function FiltrationScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [filtration, setFiltration] = useState([]);
  useEffect(() => {
    fetchFiltration();
  }, []);
  const fetchFiltration = async () => {
    const response = await fetch(API_PATHS.path_filtration);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      let newData = [];
      for (var i = 1; i <= 24; i++) {
        var fieldName = "fp_" + i.toString();
        newData.push(changeIntToBoolean(data[fieldName]));
      }
      setFiltration(newData);
    }
  };
  const changeIntToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const changeModeFiltration = (index) => {
    const newArr = [...filtration]; // 1. ก๊อปปี้ข้อมูลเดิมมาใส่ตัวแปรใหม่
    newArr[index] = !newArr[index]; // 2. แก้ไขเฉพาะตำแหน่งที่ต้องการ
    setFiltration(newArr);
    var fieldSet = "fp_" + (index + 1).toString();
    fetchUpdate(fieldSet, newArr[index] ? 1 : 0);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_filtration, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        table_set: "filtration",
        field_set: field,
        value_set: value,
      }),
    });

    ServerUpdate.update_online_pump("function_pump", field, value, 1);
  };
  return (
    <div className="container-fluid">
      <Header name={"Filtration"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">Filtration</div>
        <table className="table">
          <thead>
            <tr>
              <th> {language === "fr" ? fr_lang.hour : en_lang.hour}</th>
              <th className="text-end">Mode</th>
            </tr>
          </thead>
          <tbody>
            {Constante.hour_setting.map((item, index) => (
              <tr key={index}>
                <td>{item}</td>
                <td>
                  <div className="clearfix">
                    <div className="float-end">
                      <label className="switch">
                        <input
                          type="checkbox"
                          checked={filtration[index] || false}
                          onChange={() => changeModeFiltration(index)}
                        />
                        <span className="slider"></span>
                      </label>
                    </div>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
export default FiltrationScreen;
