import { useEffect, useState, useRef } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { Constante } from "../component/Constante";
import Swal from "sweetalert2";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";

function AcoScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [sunActive, setSunAcitve] = useState(0);
  const [monActive, setMonAcitve] = useState(0);
  const [tueActive, setTueAcitve] = useState(0);
  const [wedActive, setWedAcitve] = useState(0);
  const [thuActive, setThuAcitve] = useState(0);
  const [friActive, setFriAcitve] = useState(0);
  const [satActive, setSatAcitve] = useState(0);
  const [startTime1, setStartTime1] = useState("");
  const [stopTime1, setStopTime1] = useState("");
  const [activeTime1, setActiveTime1] = useState("");
  const [startTime2, setStartTime2] = useState("");
  const [stopTime2, setStopTime2] = useState("");
  const [activeTime2, setActiveTime2] = useState("");
  const [startTime3, setStartTime3] = useState("");
  const [stopTime3, setStopTime3] = useState("");
  const [activeTime3, setActiveTime3] = useState("");
  const [startTime4, setStartTime4] = useState("");
  const [stopTime4, setStopTime4] = useState("");
  const [activeTime4, setActiveTime4] = useState("");

  useEffect(() => {
    fetchInjection();
  }, []);
  const fetchInjection = async () => {
    const response = await fetch(API_PATHS.path_injection_week);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setSunAcitve(data.iw_sun);
      setMonAcitve(data.iw_mon);
      setTueAcitve(data.iw_tue);
      setWedAcitve(data.iw_wed);
      setThuAcitve(data.iw_thu);
      setFriAcitve(data.iw_fri);
      setSatAcitve(data.iw_sat);

      setStartTime1(data.iw_start_1);
      setStopTime1(data.iw_stop_1);
      setActiveTime1(data.iw_active_1);

      setStartTime2(data.iw_start_2);
      setStopTime2(data.iw_stop_2);
      setActiveTime2(data.iw_active_2);

      setStartTime3(data.iw_start_3);
      setStopTime3(data.iw_stop_3);
      setActiveTime3(data.iw_active_3);

      setStartTime4(data.iw_start_4);
      setStopTime4(data.iw_stop_4);
      setActiveTime4(data.iw_active_4);
    }
  };

  const changeModeWeek = (mode) => {
    var new_value = 0;
    if (mode === "sun") {
      new_value = parseInt(sunActive) === 1 ? 0 : 1;
      setSunAcitve(new_value);
      updateData("iw_sun", new_value);
    } else if (mode === "mon") {
      new_value = parseInt(monActive) === 1 ? 0 : 1;
      setMonAcitve(new_value);
      updateData("iw_mon", new_value);
    } else if (mode === "tue") {
      new_value = parseInt(tueActive) === 1 ? 0 : 1;
      setTueAcitve(new_value);
      updateData("iw_tue", new_value);
    } else if (mode === "wed") {
      new_value = parseInt(wedActive) === 1 ? 0 : 1;
      setWedAcitve(new_value);
      updateData("iw_wed", new_value);
    } else if (mode === "thu") {
      new_value = parseInt(thuActive) === 1 ? 0 : 1;
      setThuAcitve(new_value);
      updateData("iw_thu", new_value);
    } else if (mode === "fri") {
      new_value = parseInt(friActive) === 1 ? 0 : 1;
      setFriAcitve(new_value);
      updateData("iw_fri", new_value);
    } else if (mode === "sat") {
      new_value = parseInt(satActive) === 1 ? 0 : 1;
      setSatAcitve(new_value);
      updateData("iw_sat", new_value);
    }
  };
  const setStartTime = (value, field) => {
    if (field === "iw_start_1") {
      setStartTime1(value);
    } else if (field === "iw_start_2") {
      setStartTime2(value);
    } else if (field === "iw_start_3") {
      setStartTime3(value);
    } else if (field === "iw_start_4") {
      setStartTime4(value);
    }
  };
  const setStopTime = (value, field) => {
    if (field === "iw_stop_1") {
      setStopTime1(value);
    } else if (field === "iw_stop_2") {
      setStopTime2(value);
    } else if (field === "iw_stop_3") {
      setStopTime3(value);
    } else if (field === "iw_stop_4") {
      setStopTime4(value);
    }
  };
  const updateSettingWeek = (section) => {
    if (section === "time1") {
      updateData("iw_start_1", startTime1);
      updateData("iw_stop_1", stopTime1);
    } else if (section === "time2") {
      updateData("iw_start_2", startTime2);
      updateData("iw_stop_2", stopTime2);
    } else if (section === "time3") {
      updateData("iw_start_3", startTime3);
      updateData("iw_stop_3", stopTime3);
    } else if (section === "time4") {
      updateData("iw_start_4", startTime4);
      updateData("iw_stop_4", stopTime4);
    }
    Swal.fire({
      position: "top-end",
      icon: "success",
      title: "Your work has been saved",
      showConfirmButton: false,
      timer: 1500,
    });
  };
  const changeActiveMode = (section) => {
    var new_value = 0;
    if (section === "time1") {
      new_value = parseInt(activeTime1) === 1 ? 0 : 1;
      setActiveTime1(new_value);
      updateData("iw_active_1", new_value);
    } else if (section === "time2") {
      new_value = parseInt(activeTime2) === 1 ? 0 : 1;
      setActiveTime2(new_value);
      updateData("iw_active_2", new_value);
    } else if (section === "time3") {
      new_value = parseInt(activeTime3) === 1 ? 0 : 1;
      setActiveTime3(new_value);
      updateData("iw_active_3", new_value);
    } else if (section === "time4") {
      new_value = parseInt(activeTime4) === 1 ? 0 : 1;
      setActiveTime4(new_value);
      updateData("iw_active_4", new_value);
    }
    Swal.fire({
      position: "top-end",
      icon: "success",
      title: "Your work has been saved",
      showConfirmButton: false,
      timer: 1500,
    });
  };
  const updateData = (field, value) => {
    fetch(API_PATHS.path_injection_week, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        table_set: "aco",
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_online_injection_week(
      "injection_week",
      field,
      value,
      1,
    );
  };
  return (
    <div className="container-fluid">
      <Header name={"ACO Injection"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">ACO</div>
        <div className="row">
          <div className="col-12 mt-3">
            <div className="d-flex mt-3">
              <div
                className={`p-2 flex-fill text-center text-white ${
                  sunActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("sun")}
              >
                {language === "fr" ? fr_lang.sun : en_lang.sun}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  monActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("mon")}
              >
                {language === "fr" ? fr_lang.mon : en_lang.mon}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  tueActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("tue")}
              >
                {language === "fr" ? fr_lang.tue : en_lang.tue}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  wedActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("wed")}
              >
                {language === "fr" ? fr_lang.wed : en_lang.wed}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  thuActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("thu")}
              >
                {language === "fr" ? fr_lang.thu : en_lang.thu}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  friActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("fri")}
              >
                {language === "fr" ? fr_lang.fri : en_lang.fri}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  satActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("sat")}
              >
                {language === "fr" ? fr_lang.sat : en_lang.sat}
              </div>
            </div>
          </div>
        </div>
        {/* time 1 */}
        <div className="row mt-3">
          <div className="col-md-12">
            <div className="clearfix">
              <div className="float-end">
                <i
                  className={`fa fa-power-off fa-2x  ${
                    activeTime1 === 1 ? "text-success" : "text-danger"
                  }`}
                  onClick={() => changeActiveMode("time1")}
                ></i>
              </div>
            </div>
          </div>
        </div>
        <div className="row">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={startTime1}
                onChange={(e) => setStartTime(e.target.value, "iw_start_1")}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={stopTime1}
                onChange={(e) => setStopTime(e.target.value, "iw_stop_1")}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => updateSettingWeek("time1")}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
        <hr />
        {/* time 2 */}
        <div className="row mt-3">
          <div className="col-md-12">
            <div className="clearfix">
              <div className="float-end">
                <i
                  className={`fa fa-power-off fa-2x  ${
                    activeTime2 === 1 ? "text-success" : "text-danger"
                  }`}
                  onClick={() => changeActiveMode("time2")}
                ></i>
              </div>
            </div>
          </div>
        </div>
        <div className="row">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={startTime2}
                onChange={(e) => setStartTime(e.target.value, "iw_start_2")}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={stopTime2}
                onChange={(e) => setStopTime(e.target.value, "iw_stop_2")}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => updateSettingWeek("time2")}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
        <hr />
        {/* time 3 */}
        <div className="row mt-3">
          <div className="col-md-12">
            <div className="clearfix">
              <div className="float-end">
                <i
                  className={`fa fa-power-off fa-2x  ${
                    activeTime3 === 1 ? "text-success" : "text-danger"
                  }`}
                  onClick={() => changeActiveMode("time3")}
                ></i>
              </div>
            </div>
          </div>
        </div>
        <div className="row">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={startTime3}
                onChange={(e) => setStartTime(e.target.value, "iw_start_3")}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={stopTime3}
                onChange={(e) => setStopTime(e.target.value, "iw_stop_3")}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => updateSettingWeek("time3")}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
        <hr />
        {/* time 4 */}
        <div className="row mt-3">
          <div className="col-md-12">
            <div className="clearfix">
              <div className="float-end">
                <i
                  className={`fa fa-power-off fa-2x  ${
                    activeTime4 === 1 ? "text-success" : "text-danger"
                  }`}
                  onClick={() => changeActiveMode("time4")}
                ></i>
              </div>
            </div>
          </div>
        </div>
        <div className="row">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={startTime4}
                onChange={(e) => setStartTime(e.target.value, "iw_start_4")}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={stopTime4}
                onChange={(e) => setStopTime(e.target.value, "iw_stop_4")}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => updateSettingWeek("time4")}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
        <hr />
      </div>
    </div>
  );
}
export default AcoScreen;
