import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function WinterMode() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [active, setActive] = useState(0);
  const [temperature, setTemperature] = useState(0);
  const [deff, setDeff] = useState(0);
  useEffect(() => {
    fetchAdvance();
  }, []);
  const fetchAdvance = async () => {
    const response = await fetch(API_PATHS.path_advance);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setActive(data.winter_mode_active);
      setTemperature(data.winter_mode_temperature);
      setDeff(data.winter_mode_diff);
    }
  };
  const addingNumber = (field, value, type) => {
    var new_value = 0;
    if (field === "winter_mode_temperature") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value += 1;
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setTemperature(new_value);
    } else if (field === "winter_mode_diff") {
      new_value = parseInt(value);
      if (type === "plus") {
        if (new_value < 10) {
          new_value += 1;
        }
      } else {
        if (new_value > 1) {
          new_value -= 1;
        }
      }
      setDeff(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const changeMode = (value) => {
    setActive(value);
    fetchUpdate("winter_mode_active", value);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };
  return (
    <div className="container-fluid">
      <Header name={"Winter Mode"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">Winter Mode</div>
        <div className="switch-toggle switch-3 switch-candy mt-3">
          <input
            id="menu_on"
            name="menu_mode"
            type="radio"
            checked={active === 1}
            onChange={() => changeMode(1)}
          />
          <label htmlFor="menu_on">
            {language === "fr" ? fr_lang.activated : en_lang.activated}
          </label>
          <input
            id="menu_off"
            name="menu_mode"
            type="radio"
            checked={active === 0}
            onChange={() => changeMode(0)}
          />
          <label htmlFor="menu_off">
            {language === "fr" ? fr_lang.disabled : en_lang.disabled}
          </label>
          <a href=""></a>
        </div>

        <div className="row mt-2">
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_temperature
              : en_lang.water_temperature}{" "}
            (Heating)
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addingNumber("winter_mode_temperature", temperature, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {temperature}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addingNumber("winter_mode_temperature", temperature, "plus")
                }
              ></i>
            </div>
          </div>
        </div>

        <div className="row mt-2">
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            {language === "fr"
              ? fr_lang.differential_cutoff_temperature
              : en_lang.differential_cutoff_temperature}{" "}
            [ 1 - 10 ]
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() => addingNumber("winter_mode_diff", deff, "minus")}
              ></i>
              <div className="p-2 font-size-middle content-color">{deff}</div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() => addingNumber("winter_mode_diff", deff, "plus")}
              ></i>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default WinterMode;
