import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import Swal from "sweetalert2";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";

function BackwashScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [manualTime, setManualTime] = useState(10);
  const [backwashMode, setBackwashMode] = useState(0);
  const [sunActive, setSunActive] = useState(0);
  const [monActive, setMonActive] = useState(0);
  const [tueActive, setTueActive] = useState(0);
  const [wedActive, setWedActive] = useState(0);
  const [thuActive, setThuActive] = useState(0);
  const [friActive, setFriActive] = useState(0);
  const [satActive, setSatActive] = useState(0);
  const [startTime, setStartTime] = useState("");
  const [stopTime, setStopTime] = useState("");
  const [openActive, setOpenActive] = useState(0);
  const [autoTime, setAutoTime] = useState(10);
  useEffect(() => {
    fetchBackwash();
  }, []);
  const fetchBackwash = async () => {
    const response = await fetch(API_PATHS.path_backwash);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.backwash[0];
      setBackwashMode(data.fb_mode);
      setManualTime(data.fb_manual_time);
      setAutoTime(data.fb_auto_time);
      setSunActive(data.fb_sun);
      setMonActive(data.fb_mon);
      setTueActive(data.fb_tue);
      setWedActive(data.fb_wed);
      setThuActive(data.fb_thu);
      setFriActive(data.fb_fri);
      setSatActive(data.fb_sat);
      setStartTime(data.fb_start);
      setStopTime(data.fb_stop);
      setOpenActive(data.fb_active);
    }
  };
  const changeMode = (mode) => {
    setBackwashMode(mode);
    fetchUpdate("fb_mode", mode);
  };
  const adddingNumber = (field, value, type) => {
    var new_value = parseInt(value);
    if (field === "fb_manual_time") {
      if (type === "plus") {
        new_value++;
      } else {
        if (new_value > 5) {
          new_value--;
        }
      }
      setManualTime(new_value);
    } else if (field === "fb_auto_time") {
      if (type === "plus") {
        new_value++;
      } else {
        if (new_value > 5) {
          new_value--;
        }
      }
      setAutoTime(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const changeModeWeek = (week) => {
    if (week === "sun") {
      setSunActive(sunActive === 1 ? 0 : 1);
      fetchUpdate("fb_sun", sunActive === 1 ? 0 : 1);
    }
    if (week === "mon") {
      setMonActive(monActive === 1 ? 0 : 1);
      fetchUpdate("fb_mon", monActive === 1 ? 0 : 1);
    }
    if (week === "tue") {
      setTueActive(tueActive === 1 ? 0 : 1);
      fetchUpdate("fb_tue", tueActive === 1 ? 0 : 1);
    }
    if (week === "wed") {
      setWedActive(wedActive === 1 ? 0 : 1);
      fetchUpdate("fb_wed", wedActive === 1 ? 0 : 1);
    }
    if (week === "thu") {
      setThuActive(thuActive === 1 ? 0 : 1);
      fetchUpdate("fb_thu", thuActive === 1 ? 0 : 1);
    }
    if (week === "fri") {
      setFriActive(friActive === 1 ? 0 : 1);
      fetchUpdate("fb_fri", friActive === 1 ? 0 : 1);
    }
    if (week === "sat") {
      setSatActive(satActive === 1 ? 0 : 1);
      fetchUpdate("fb_sat", satActive === 1 ? 0 : 1);
    }
  };
  const updateSettingWeek = () => {
    fetchUpdate("fb_start", startTime);
    fetchUpdate("fb_stop", stopTime);
    Swal.fire({
      position: "top-end",
      icon: "success",
      title: "Your work has been saved",
      showConfirmButton: false,
      timer: 1500,
    });
  };
  const changeActiveMode = () => {
    var new_value = openActive === 1 ? 0 : 1;
    setOpenActive(new_value);
    fetchUpdate("fb_active", new_value);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_backwash, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_backwash", field, value);
  };
  return (
    <div className="container-fluid">
      <Header name={"Backwash"} />
      <div className="row mt-3">
        <div className="col-12">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">Mode</div>
            <div className="switch-toggle switch-3 switch-candy mt-3">
              <input
                id="menu_manual"
                name="menu_mode"
                type="radio"
                checked={backwashMode === 1}
                onChange={() => changeMode(1)}
              />
              <label htmlFor="menu_manual">
                {language === "fr" ? fr_lang.manual : en_lang.manual}
              </label>
              <input
                id="menu_off"
                name="menu_mode"
                type="radio"
                checked={backwashMode === 0}
                onChange={() => changeMode(0)}
              />
              <label htmlFor="menu_off">
                {language === "fr" ? fr_lang.close : en_lang.close}
              </label>
              <input
                id="menu_auto"
                name="menu_mode"
                type="radio"
                checked={backwashMode === 2}
                onChange={() => changeMode(2)}
              />
              <label htmlFor="menu_auto">Auto</label>
              <a href=""></a>
            </div>
          </div>
        </div>
        <div className="col-12 mt-3">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">
              {language === "fr" ? fr_lang.manual : en_lang.manual} Time
            </div>
            <div className="row">
              <div className="col-md-7  font-size-middle  align-self-center content-color">
                Start (sec.)
              </div>
              <div className="col-md-5 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() =>
                      adddingNumber("fb_manual_time", manualTime, "minus")
                    }
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {manualTime}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() =>
                      adddingNumber("fb_manual_time", manualTime, "plus")
                    }
                  ></i>
                </div>
              </div>
            </div>
          </div>
        </div>
        <div className="col-12 mt-3">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">Auto Time</div>
            <div className="row">
              <div className="col-md-7  font-size-middle  align-self-center content-color">
                Start (sec.)
              </div>
              <div className="col-md-5 ">
                <div className="d-flex justify-content-between align-items-center">
                  <i
                    className="fa fa-minus-circle fa-3x text-danger p-2"
                    onClick={() =>
                      adddingNumber("fb_auto_time", autoTime, "minus")
                    }
                  ></i>
                  <div className="p-2 font-size-middle content-color">
                    {autoTime}
                  </div>
                  <i
                    className="fa fa-plus-circle fa-3x text-success p-2"
                    onClick={() =>
                      adddingNumber("fb_auto_time", autoTime, "plus")
                    }
                  ></i>
                </div>
              </div>
            </div>
          </div>
        </div>
        <div className="col-12 mt-3 mb-5">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">
              {language === "fr"
                ? fr_lang.backwash_schedule
                : en_lang.backwash_schedule}
            </div>
            <div className="row mt-3">
              <div className="col-md-12">
                <div className="clearfix">
                  <div className="float-end">
                    <i
                      className={`fa fa-power-off fa-2x  ${
                        openActive === 1 ? "text-success" : "text-danger"
                      }`}
                      onClick={() => changeActiveMode()}
                    ></i>
                  </div>
                </div>
              </div>
            </div>
            <div className="d-flex mt-3">
              <div
                className={`p-2 flex-fill text-center text-white ${
                  sunActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("sun")}
              >
                {language === "fr" ? fr_lang.sun : en_lang.sun}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  monActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("mon")}
              >
                {language === "fr" ? fr_lang.mon : en_lang.mon}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  tueActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("tue")}
              >
                {language === "fr" ? fr_lang.tue : en_lang.tue}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  wedActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("wed")}
              >
                {language === "fr" ? fr_lang.wed : en_lang.wed}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  thuActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("thu")}
              >
                {language === "fr" ? fr_lang.thu : en_lang.thu}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  friActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("fri")}
              >
                {language === "fr" ? fr_lang.fri : en_lang.fri}
              </div>
              <div
                className={`p-2 flex-fill text-center text-white ${
                  satActive !== 1 ? "bg-dark" : "bg-danger"
                }`}
                onClick={() => changeModeWeek("sat")}
              >
                {language === "fr" ? fr_lang.sat : en_lang.sat}
              </div>
            </div>

            <div className="row mt-3">
              <div className="col-md-6">
                <div className="form-group">
                  <label className="text-dark">
                    {language === "fr" ? fr_lang.startup : en_lang.startup} :
                  </label>
                  <input
                    type="time"
                    className="form-control"
                    step="2"
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                  />
                </div>
              </div>
              <div className="col-md-6">
                <div className="form-group">
                  <label className="text-dark">
                    {language === "fr" ? fr_lang.close : en_lang.close} :
                  </label>
                  <input
                    type="time"
                    className="form-control"
                    step="2"
                    value={stopTime}
                    onChange={(e) => setStopTime(e.target.value)}
                  />
                </div>
              </div>
              <div className="col-md-12 mt-3 ">
                <div className="clearfix">
                  <div className="float-end">
                    <button
                      className="btn btn-primary"
                      onClick={() => updateSettingWeek()}
                    >
                      <i className="fa fa-save"></i> Save
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default BackwashScreen;
