import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import { Constante } from "../component/Constante";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function OzonePumpScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [filtration, setFiltration] = useState([]);
  const [timeSelect, setTimeSelect] = useState([]);

  useEffect(() => {
    fetchFiltration();
  }, []);
  const fetchFiltration = async () => {
    const response = await fetch(API_PATHS.path_filtration);
    const result = await response.json();
    const response_machine_option = await fetch(API_PATHS.path_machine_option);
    const result_machine_option = await response_machine_option.json();

    if (result.status === 200) {
      const data = result.data.dataInfo[3];
      const filtrationTime = result.data.dataInfo[0];
      const machine_option = result_machine_option.data.machine_option[0];
      const pump_2 = result.data.dataInfo[4];

      let newData = [];
      let newFiltration = [];
      for (var i = 1; i <= 24; i++) {
        var fieldName = "fp_" + i.toString();
        newData.push(changeIntToBoolean(data[fieldName]));
        if (parseInt(machine_option.pump) === 0) {
          newFiltration.push(changeIntToBoolean(filtrationTime[fieldName]));
        } else {
          if (
            changeIntToBoolean(pump_2[fieldName]) ||
            changeIntToBoolean(filtrationTime[fieldName])
          ) {
            newFiltration.push(true);
          } else {
            newFiltration.push(false);
          }
        }
      }
      setTimeSelect(newFiltration);
      setFiltration(newData);
    }
  };
  const changeIntToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const changeModeFiltration = (index) => {
    const newArr = [...filtration]; // 1. ก๊อปปี้ข้อมูลเดิมมาใส่ตัวแปรใหม่
    newArr[index] = !newArr[index]; // 2. แก้ไขเฉพาะตำแหน่งที่ต้องการ
    setFiltration(newArr);
    var fieldSet = "fp_" + (index + 1).toString();
    fetchUpdate(fieldSet, newArr[index] ? 1 : 0);
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_filtration, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        table_set: "ozone_pump",
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_online_pump("function_pump", field, value, 4);
  };
  return (
    <div className="container-fluid">
      <Header name={"Ozone Pump"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.pump_ozone : en_lang.pump_ozone}
        </div>
        <table className="table">
          <thead>
            <tr>
              <th>{language === "fr" ? fr_lang.hour : en_lang.hour}</th>
              <th className="text-end">Mode</th>
            </tr>
          </thead>
          <tbody>
            {Constante.hour_setting.map((item, index) => (
              <tr key={index}>
                <td>{item}</td>
                <td>
                  <div
                    className={`clearfix ${timeSelect[index] ? "" : "d-none"}`}
                  >
                    <div className="float-end">
                      <label className="switch">
                        <input
                          type="checkbox"
                          checked={filtration[index] || false}
                          onChange={() => changeModeFiltration(index)}
                        />
                        <span className="slider"></span>
                      </label>
                    </div>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
export default OzonePumpScreen;
