import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import Swal from "sweetalert2";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function HeatPumpScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [realTimeTemp, setRealTimeTemp] = useState("");
  const [heatPumpActive, setHeatPumpActive] = useState(0);
  const [tempHeating, setTempHeating] = useState(0);
  const [tempCooling, setTempCooling] = useState(0);
  const [heatpumpHeating, setHeatpumpHeating] = useState(false);
  const [heatpumpCooling, setHeatpumpCooling] = useState(false);
  const [startTime, setStartTime] = useState("");
  const [stopTime, setStopTime] = useState("");
  useEffect(() => {
    fetchAdvance();
    fetchSetting();
    // fetchDashboard();
    // const interval = setInterval(fetchDashboard, 3000);
    // return () => clearInterval(interval);
  }, []);
  const fetchSetting = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      if (parseInt(data.heatpump_heating) === 1) {
        setHeatpumpHeating(true);
      } else {
        setHeatpumpHeating(false);
      }

      if (parseInt(data.heatpump_cooling) === 1) {
        setHeatpumpCooling(true);
      } else {
        setHeatpumpCooling(false);
      }
    }
  };
  const fetchDashboard = async () => {
    const response = await fetch(API_PATHS.path_dashboard);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data;
      setRealTimeTemp(data.temperature);
    }
  };
  const fetchAdvance = async () => {
    const response = await fetch(API_PATHS.path_advance);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setHeatPumpActive(data.heat_pump_mode);
      setTempHeating(data.heat_pump_heating);
      setTempCooling(data.heat_pump_cooling);
      setStartTime(data.heatpump_start);
      setStopTime(data.heatpump_stop);
    }
  };
  const changeModeHeatPump = (value) => {
    setHeatPumpActive(value);
    fetchUpdate("heat_pump_mode", value);
  };
  const addingNumber = (field, value, type) => {
    var new_value = 0;
    if (field === "heat_pump_heating") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value++;
      } else {
        if (new_value > 1) {
          new_value--;
        }
      }
      setTempHeating(new_value);
    } else if (field === "heat_pump_cooling") {
      new_value = parseInt(value);
      if (type === "plus") {
        new_value++;
      } else {
        if (new_value > 1) {
          new_value--;
        }
      }
      setTempCooling(new_value);
    }
    fetchUpdate(field, new_value);
  };
  const updateSettingWeek = () => {
    fetchUpdate("heatpump_start", startTime);
    fetchUpdate("heatpump_stop", stopTime);
    Swal.fire({
      position: "top-end",
      icon: "success",
      title: "Your work has been saved",
      showConfirmButton: false,
      timer: 1500,
    });
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };

  return (
    <div className="container-fluid">
      <Header
        name={`${language === "fr" ? fr_lang.heat_pump : en_lang.heat_pump}`}
      />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.temperature : en_lang.temperature}
        </div>
        <div className="d-flex justify-content-between mt-3">
          <div className="text-dark font-size-middle">
            {language === "fr" ? fr_lang.temperature : en_lang.temperature} :
          </div>
          <div className="text-dark font-size-middle">{realTimeTemp}</div>
        </div>
      </div>
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.heat_pump : en_lang.heat_pump}
        </div>
        <div className="switch-toggle switch-3 switch-candy mt-3">
          <input
            id="menu_on"
            name="menu_mode"
            type="radio"
            checked={heatPumpActive === 1}
            onChange={() => changeModeHeatPump(1)}
          />
          <label htmlFor="menu_on">
            {language === "fr" ? fr_lang.activated : en_lang.activated}
          </label>
          <input
            id="menu_off"
            name="menu_mode"
            type="radio"
            checked={heatPumpActive === 0}
            onChange={() => changeModeHeatPump(0)}
          />
          <label htmlFor="menu_off">
            {language === "fr" ? fr_lang.disabled : en_lang.disabled}
          </label>
          <a href=""></a>
        </div>

        <div className={`row mt-2 ${heatpumpHeating ? "" : "d-none"}`}>
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_temperature
              : en_lang.water_temperature}{" "}
            (Heating)
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addingNumber("heat_pump_heating", tempHeating, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {tempHeating}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addingNumber("heat_pump_heating", tempHeating, "plus")
                }
              ></i>
            </div>
          </div>
        </div>
        <div className={`row mt-2 ${heatpumpCooling ? "" : "d-none"}`}>
          <div className="col-md-6  font-size-middle  align-self-center content-color">
            {language === "fr"
              ? fr_lang.water_temperature
              : en_lang.water_temperature}{" "}
            (Cooling)
          </div>
          <div className="col-md-6 ">
            <div className="d-flex justify-content-between align-items-center">
              <i
                className="fa fa-minus-circle fa-3x text-danger p-2"
                onClick={() =>
                  addingNumber("heat_pump_cooling", tempCooling, "minus")
                }
              ></i>
              <div className="p-2 font-size-middle content-color">
                {tempCooling}
              </div>
              <i
                className="fa fa-plus-circle fa-3x text-success p-2"
                onClick={() =>
                  addingNumber("heat_pump_cooling", tempCooling, "plus")
                }
              ></i>
            </div>
          </div>
        </div>
      </div>

      <div className="box-glass p-2 h-100 mt-3 mb-5">
        <div className="box-container-header ">
          {language === "fr" ? fr_lang.set_heat_pump : en_lang.set_heat_pump}
        </div>
        <div className="row">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-white">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-white">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                step="2"
                value={stopTime}
                onChange={(e) => setStopTime(e.target.value)}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => updateSettingWeek()}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default HeatPumpScreen;
