import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import Header from "../component/Header";
import { Modal } from "bootstrap";
import { API_PATHS } from "../component/PathApi";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function Menu() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const modalRef = useRef();
  const modalInstance = useRef();
  const navigate = useNavigate();
  const [selectionName, setSelectionName] = useState("");
  const [activeMode, setActiveMode] = useState(0);
  const [fieldName, setFieldName] = useState("");

  const [heater, setHeater] = useState(false);
  const [pH, setPH] = useState(false);
  const [orp, setOrp] = useState(false);
  const [aco, setAco] = useState(false);
  const [oxyGen, setOxyGen] = useState(false);
  const [oxyGenWeek, setOxygenWeek] = useState(false);
  const [apf, setApf] = useState(false);
  const [apfWeek, setApfWeek] = useState(false);
  const [ozonePump, setOzonePump] = useState(false);
  const [uvLamp, setUVLamp] = useState(false);
  const [ozoneLamp, setOzoneLamp] = useState(false);
  const [pump, setPump] = useState(false);
  const [chlorine, setChlorine] = useState(false);
  const [chlorineWeek, setChlorineWeek] = useState(false);
  const [backwash, setBackwash] = useState(false);
  const [heatPump, setHeatPump] = useState(false);
  const [nightTime, setNightTime] = useState(false);

  const gotoPage = (slug) => {
    navigate("/" + slug);
  };
  useEffect(() => {
    fetchSetting();
    modalInstance.current = new Modal(modalRef.current);
  }, []);

  const fetchSetting = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      setHeater(changeNumberToBoolean(data.heater_1));
      setPH(changeNumberToBoolean(data.ph));
      setOrp(changeNumberToBoolean(data.orp));
      setAco(changeNumberToBoolean(data.aco));
      setOxyGen(changeNumberToBoolean(data.oxygen));
      setApf(changeNumberToBoolean(data.apf));
      setOzonePump(changeNumberToBoolean(data.ozone_pump));
      setUVLamp(changeNumberToBoolean(data.uv_lamp));
      setOzoneLamp(changeNumberToBoolean(data.ozone_lamp));
      setPump(changeNumberToBoolean(data.pump));
      setChlorine(changeNumberToBoolean(data.chlorine));
      setBackwash(changeNumberToBoolean(data.backwash));
      setOxygenWeek(changeNumberToBoolean(data.oxygen_week));
      setApfWeek(changeNumberToBoolean(data.apf_week));
      setChlorineWeek(changeNumberToBoolean(data.chlorine_week));
      setNightTime(changeNumberToBoolean(data.night_time));
      if (
        changeNumberToBoolean(data.heatpump_heating) ||
        changeNumberToBoolean(data.heatpump_cooling)
      ) {
        setHeatPump(true);
      } else {
        setHeatPump(false);
      }
    }
  };
  const changeNumberToBoolean = (value) => {
    if (parseInt(value) === 1) {
      return true;
    } else {
      return false;
    }
  };
  const showModal = () => modalInstance.current.show();
  const hideModal = () => modalInstance.current.hide();
  const navigateLinkSetting = () => {
    if (fieldName === "fm_filtration") {
      navigate("/filtration");
    } else if (fieldName === "fm_ozone_lamp") {
      navigate("/ozone_lamp");
    } else if (fieldName === "fm_uv_lamp") {
      navigate("/uv_lamp");
    } else if (fieldName === "fm_ozone_pump") {
      navigate("/ozone_pump");
    } else if (fieldName === "fm_pump_2") {
      navigate("/second_pump");
    }
    hideModal();
  };
  const selectionMode = async (menuName) => {
    const response = await fetch(API_PATHS.path_mode);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      if (menuName === "filtration") {
        setFieldName("fm_filtration");
        setActiveMode(data.fm_filtration);
      } else if (menuName === "uv lamp 1") {
        setFieldName("fm_ozone_lamp");
        setActiveMode(data.fm_ozone_lamp);
      } else if (menuName === "uv lamp 2") {
        setFieldName("fm_uv_lamp");
        setActiveMode(data.fm_uv_lamp);
      } else if (menuName === "ozone pump") {
        setFieldName("fm_ozone_pump");
        setActiveMode(data.fm_ozone_pump);
      } else if (menuName === "pump 2") {
        setFieldName("fm_pump_2");
        setActiveMode(data.fm_pump_2);
      }
    }
    setSelectionName(menuName);
    showModal();
  };
  const changeMode = (value) => {
    setActiveMode(value);
    fetch(API_PATHS.path_mode, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: fieldName,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_mode", fieldName, value);
  };
  return (
    <div className="container-fluid">
      <Header name={"Menu"} />
      <div className="row g-1 mt-3 mb-3">
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => gotoPage("")}>
            <img
              src={require("../assets/images/Dashboard.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => selectionMode("filtration")}>
            <img
              src={require("../assets/images/Filtration pump.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${pump ? "" : "d-none"}`}>
          <div onClick={() => selectionMode("pump 2")}>
            <img
              src={require("../assets/images/Pump2.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${backwash ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("backwash")}>
            <img
              src={require("../assets/images/Backwash.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${ozoneLamp ? "" : "d-none"}`}>
          <div onClick={() => selectionMode("uv lamp 1")}>
            <img
              src={require("../assets/images/UV Lampe 1.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${uvLamp ? "" : "d-none"}`}>
          <div onClick={() => selectionMode("uv lamp 2")}>
            <img
              src={require("../assets/images/UV Lampe 2.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${pH ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("ph")}>
            <img
              src={require("../assets/images/PH.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${aco ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("aco")}>
            <img
              src={require("../assets/images/ACO.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${orp ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("orp")}>
            <img
              src={require("../assets/images/ORP.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${chlorine ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("chlorine")}>
            <img
              src={require("../assets/images/Chlorine.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${chlorineWeek ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("chlorine_week")}>
            <img
              src={require("../assets/images/Chlorine.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${oxyGen ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("oxygen")}>
            <img
              src={require("../assets/images/Oxygen.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${oxyGenWeek ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("oxygen_week")}>
            <img
              src={require("../assets/images/Oxygen.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${apf ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("apf")}>
            <img
              src={require("../assets/images/APF.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${apfWeek ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("apf_week")}>
            <img
              src={require("../assets/images/APF.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${ozonePump ? "" : "d-none"}`}>
          <div onClick={() => selectionMode("ozone pump")}>
            <img
              src={require("../assets/images/Ozone pump.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${heater ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("heater")}>
            <img
              src={require("../assets/images/Heater.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${heatPump ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("heatpump")}>
            <img
              src={require("../assets/images/Heat pump.png")}
              className="menu-image"
            />
          </div>
        </div>

        <div className={`col-md-4 col-6 p-1 ${heater ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("winter_mode")}>
            <img
              src={require("../assets/images/Winter mode.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => gotoPage("advance")}>
            <img
              src={require("../assets/images/Advance.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className={`col-md-4 col-6 p-1 ${nightTime ? "" : "d-none"}`}>
          <div onClick={() => gotoPage("night_time")}>
            <img
              src={require("../assets/images/Night time.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => gotoPage("diagnostic")}>
            <img
              src={require("../assets/images/Diagnostic.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => gotoPage("logger")}>
            <img
              src={require("../assets/images/Data log.png")}
              className="menu-image"
            />
          </div>
        </div>
        <div className="col-md-4 col-6 p-1">
          <div onClick={() => gotoPage("setting")}>
            <img
              src={require("../assets/images/Setting.png")}
              className="menu-image"
            />
          </div>
        </div>
      </div>
      {/* 24 */}
      <div className="modal fade" ref={modalRef} tabIndex="-1">
        <div className="modal-dialog modal-fullscreen">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Mode {selectionName}</h5>
              <button
                type="button"
                className="btn-close"
                onClick={hideModal}
              ></button>
            </div>
            <div className="modal-body">
              <div className="switch-toggle switch-3 switch-candy mt-3">
                <input
                  id="menu_manual"
                  name="menu_mode"
                  type="radio"
                  checked={activeMode === 1}
                  onChange={() => changeMode(1)}
                />
                <label htmlFor="menu_manual">
                  {language === "fr" ? fr_lang.manual : en_lang.manual}
                </label>
                <input
                  id="menu_off"
                  name="menu_mode"
                  type="radio"
                  checked={activeMode === 0}
                  onChange={() => changeMode(0)}
                />
                <label htmlFor="menu_off">
                  {language === "fr" ? fr_lang.close : en_lang.close}
                </label>
                <input
                  id="menu_auto"
                  name="menu_mode"
                  type="radio"
                  checked={activeMode === 2}
                  onChange={() => changeMode(2)}
                />
                <label htmlFor="menu_auto">Auto</label>
                <a href=""></a>
              </div>
              <button
                className="btn btn-info mt-5 text-white form-control"
                onClick={() => navigateLinkSetting()}
              >
                {language === "fr" ? fr_lang.setting : en_lang.setting}
              </button>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={hideModal}>
                Close
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Menu;
