import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
function Header(props) {
  const navigate = useNavigate();
  const [lang, setLang] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });

  const gotoMenu = (slug) => {
    navigate("/menu");
  };
  const setLanguge = (e) => {
    setLang(e.target.value);
    sessionStorage.setItem("language", e.target.value);
    console.log(e.target.value);
  };
  return (
    <div className="d-flex justify-content-start align-items-center position-relative">
      <div className="position-absolute start-0">
        <img
          src={require("../assets/menu.png")}
          className="image-menu"
          alt=""
          onClick={gotoMenu}
        />
      </div>
      <div className="w-100 text-center">
        <h1 className="text-dark f-title">{props.name}</h1>
      </div>
      <div className="position-absolute end-0">
        <select
          className="selection-language"
          value={lang}
          onChange={(e) => setLanguge(e)}
        >
          <option value="fr">FR</option>
          <option value="en">EN</option>
        </select>
      </div>
    </div>
  );
}
export default Header;
