import { useEffect, useState, useRef } from "react";
import Header from "../component/Header";
import { API_PATHS } from "../component/PathApi";
import { en_lang, fr_lang } from "../component/Languages";
function DiagnosticScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [datetime, setDatetime] = useState("");
  const [temperature, setTemperature] = useState("");
  const [pressure, setPressure] = useState("");
  const [plcOut, setPlcOut] = useState([]);
  const [plcDC, setPlcDC] = useState([]);
  const [plcAC, setPlcAC] = useState([]);
  const [heaterHeating, setHeaterHeating] = useState("");
  const [heatpumpHeating, setHeatpumpHeating] = useState("");
  const [heatpumpCooling, sethHatpumpCooling] = useState("");
  const [pressureMin, setPressureMin] = useState("");
  const [pressureMax, setPressureMax] = useState("");
  const [heaterMode, setHeaterMode] = useState("");
  const [heatPumpMode, setHeatPumpMode] = useState("");
  const [controlPressure, setControlPressure] = useState("");
  const [controlFiltration, setControlFiltration] = useState("");
  const [controlBackwash, setControlBackwash] = useState("");
  const [statusLunshin, setStatusLunshin] = useState("Filtration");
  const [flowSensor, setFlowSensor] = useState("");
  useEffect(() => {
    loadingDashboard();
    loadingSetting();
    const interval = setInterval(loadingDashboard, 3000);
    return () => clearInterval(interval);
  }, []);
  const loadingSetting = async () => {
    const response_advance = await fetch(API_PATHS.path_advance);
    const result_advance = await response_advance.json();

    const response_mode = await fetch(API_PATHS.path_mode);
    const result_mode = await response_mode.json();

    const response_backwash = await fetch(API_PATHS.path_backwash);
    const result_backwash = await response_backwash.json();
    if (result_backwash.status === 200) {
      const data_advance = result_advance.data.dataInfo[0];
      const data_mode = result_mode.data.dataInfo[0];
      const data_backwash = result_backwash.data.backwash[0];
      setHeaterHeating(data_advance.heater_temperature);
      setHeatpumpHeating(data_advance.heat_pump_heating);
      sethHatpumpCooling(data_advance.heat_pump_cooling);
      setPressureMin(data_advance.low_pressure);
      setPressureMax(data_advance.max_pressure);
      if (parseInt(data_advance.heater_mode) === 0) {
        setHeaterMode("Arr");
      } else {
        setHeaterMode("Mar");
      }
      if (parseInt(data_advance.heat_pump_mode) === 0) {
        setHeatPumpMode("Arr");
      } else {
        setHeatPumpMode("Mar");
      }
      setControlPressure(
        parseInt(data_mode.fm_bypass_pressure) === 0 ? "Deactivé" : "Activé",
      );
      if (parseInt(data_mode.fm_filtration) === 0) {
        setControlFiltration("Arr");
      } else if (parseInt(data_mode.fm_filtration) === 1) {
        setControlFiltration("Man");
      } else {
        setControlFiltration("Auto");
      }
      if (parseInt(data_backwash.fb_mode) === 0) {
        setControlBackwash("Arr");
      } else if (parseInt(data_backwash.fb_mode) === 0) {
        setControlBackwash("Man");
      } else {
        setControlBackwash("Auto");
      }
    }
  };
  const loadingDashboard = async () => {
    const response = await fetch(API_PATHS.path_dashboard);
    const result = await response.json();

    if (result.status === 200) {
      const data = result.data;

      const now = new Date();
      const year = now.getFullYear(); // 2025
      const month = now.getMonth() + 1; // 10 (January is 0, November is 10)
      const dayOfMonth = now.getDate();
      const hours = now.getHours(); // 9
      const minutes = now.getMinutes(); // 13
      const seconds = now.getSeconds(); // 0
      const txt_time =
        dayOfMonth +
        "-" +
        month +
        "-" +
        year +
        " " +
        hours +
        ":" +
        minutes +
        ":" +
        seconds;
      setDatetime(txt_time);
      setTemperature(data.temperature);
      setPressure(data.pressure);
      var arr_in = [];
      var arr_out = [];
      var arr_ac = [];
      const split_in_ac = data.plc_in_ac.split(",");
      const split_in_dc = data.plc_in_dc.split(",");
      const split_all_out = data.plc_out.split(",");

      for (var i = 0; i <= 7; i++) {
        if (i < 3) {
          if (removeStingArr(split_in_dc[i]) === "True") {
            arr_in.push(1);
          } else {
            arr_in.push(0);
          }
          if (i < 2) {
            arr_ac.push(removeStingArr(split_in_ac[i]) + ",");
          } else {
            arr_ac.push(removeStingArr(split_in_ac[i]));
          }
        }
        if (removeStingArr(split_all_out[i]) === "True") {
          arr_out.push(1);
        } else {
          arr_out.push(0);
        }
      }
      setPlcOut(arr_out);
      setPlcDC(arr_in);
      setPlcAC(arr_ac);
      if (parseInt(data.status_backwash) === 1) {
        setStatusLunshin("Filtration");
      } else if (parseInt(data.status_backwash) === 3) {
        setStatusLunshin("Backwash");
      } else if (parseInt(data.status_backwash) === 7) {
        setStatusLunshin("Rinse");
      } else if (parseInt(data.status_backwash) === 9) {
        setStatusLunshin("Waste");
      } else if (parseInt(data.status_backwash) === 10) {
        setStatusLunshin("Recircution");
      } else if (parseInt(data.status_backwash) === 11) {
        setStatusLunshin("Close");
      } else if (parseInt(data.status_backwash) === 16) {
        setStatusLunshin("Switching");
      }
      setFlowSensor(data.flow_sensor);
    }
  };
  const removeStingArr = (value) => {
    return value.replace("[", "").replace("]", "").trim();
  };
  return (
    <div className="container-fluid">
      <Header name={"Diagnostic"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">Diagnostic</div>
        <div className="box-glass p-2 h-100 mt-2">
          <div className="d-flex justify-content-between mt-3">
            <div className="text-dark font-size-small">
              {language === "fr" ? fr_lang.date_time : en_lang.date_time}
            </div>
            <div className="text-dark font-size-small">{datetime}</div>
          </div>
        </div>

        <div className="row mt-3">
          <div className="col-md-12 col-12">
            <div className="box-glass p-2 h-100">
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.water_temperature
                    : en_lang.water_temperature}{" "}
                  (°C)
                </div>
                <div className="text-dark font-size-small">{temperature}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.heating_temperature_set
                    : en_lang.heating_temperature_set}{" "}
                  (°C)
                </div>
                <div className="text-dark font-size-small">{heaterHeating}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.heating_temperature_set
                    : en_lang.heating_temperature_set}{" "}
                  Heatpump (°C)
                </div>
                <div className="text-dark font-size-small">
                  {heatpumpHeating}
                </div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.cooling_temperature_set
                    : en_lang.cooling_temperature_set}{" "}
                  Heatpump (°C)
                </div>
                <div className="text-dark font-size-small">
                  {heatpumpCooling}
                </div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.pressure : en_lang.pressure}{" "}
                  (Bar)
                </div>
                <div className="text-dark font-size-small">{pressure}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.pressure : en_lang.pressure} mini
                  (Bar)
                </div>
                <div className="text-dark font-size-small">{pressureMin}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.pressure : en_lang.pressure} maxi
                  (Bar)
                </div>
                <div className="text-dark font-size-small">{pressureMax}</div>
              </div>
            </div>
          </div>
        </div>
        <div className="row mt-3">
          <div className="col-md-12 col-12">
            <div className="box-glass p-2 h-100">
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.mode_filtration
                    : en_lang.mode_filtration}{" "}
                  (Man / Arr / Auto)
                </div>
                <div className="text-dark font-size-small">
                  {controlFiltration}
                </div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.mode_backwash
                    : en_lang.mode_backwash}{" "}
                  (Man / Arr / Auto)
                </div>
                <div className="text-dark font-size-small">
                  {controlBackwash}
                </div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.heater : en_lang.heater}{" "}
                  (Mar/Arr)
                </div>
                <div className="text-dark font-size-small">{heaterMode}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  Heatpump (Mar/Arr)
                </div>
                <div className="text-dark font-size-small">{heatPumpMode}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr"
                    ? fr_lang.pressure_control
                    : en_lang.pressure_control}{" "}
                  ({language === "fr" ? fr_lang.activated : en_lang.activated}/
                  {language === "fr" ? fr_lang.disabled : en_lang.disabled})
                </div>
                <div className="text-dark font-size-small">
                  {controlPressure}
                </div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.plc_input : en_lang.plc_input}{" "}
                  (AC)
                </div>
                <div className="text-dark font-size-small">{plcAC}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.plc_input : en_lang.plc_input}{" "}
                  (DC)
                </div>
                <div className="text-dark font-size-small">{plcDC}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">
                  {language === "fr" ? fr_lang.plc_output : en_lang.plc_output}
                </div>
                <div className="text-dark font-size-small">{plcOut}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">Status Backwash</div>
                <div className="text-dark font-size-small">{statusLunshin}</div>
              </div>
              <div className="d-flex justify-content-between mt-3">
                <div className="text-dark font-size-small">Flow Sensor</div>
                <div className="text-dark font-size-small">{flowSensor}</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default DiagnosticScreen;
