import { useEffect, useState } from "react";
import { API_PATHS } from "../component/PathApi";
import Header from "../component/Header";
import Swal from "sweetalert2";
import { ServerUpdate } from "../component/ServerUpdate";
import { en_lang, fr_lang } from "../component/Languages";
function NightTimeScreen() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [nightTimeActive, setNightTimeActive] = useState(0);
  const [nightTimeStart, setNightTimeStart] = useState("");
  const [nightTimeStop, setNightTimeStop] = useState("");
  useEffect(() => {
    fetchAdvance();
  }, []);
  const fetchAdvance = async () => {
    const response = await fetch(API_PATHS.path_advance);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.dataInfo[0];
      setNightTimeActive(data.night_time_active);
      setNightTimeStart(data.night_time_start);
      setNightTimeStop(data.night_time_stop);
    }
  };
  const changeMode = (mode) => {
    setNightTimeActive(mode);
    fetchUpdate("night_time_active", mode);
  };
  const saveNightTime = () => {
    fetchUpdate("night_time_start", nightTimeStart);
    fetchUpdate("night_time_stop", nightTimeStop);
    Swal.fire({
      position: "top-end",
      icon: "success",
      title: "Your work has been saved",
      showConfirmButton: false,
      timer: 1500,
    });
  };
  const fetchUpdate = (field, value) => {
    fetch(API_PATHS.path_advance, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        field_set: field,
        value_set: value,
      }),
    });
    ServerUpdate.update_table("function_advance", field, value);
  };
  return (
    <div className="container-fluid">
      <Header name={"Night Time"} />
      <div className="box-glass p-2 h-100 mt-3">
        <div className="box-container-header ">Night Time</div>
        <div className="switch-toggle switch-3 switch-candy mt-3">
          <input
            id="menu_on"
            name="menu_mode"
            type="radio"
            checked={nightTimeActive === 1}
            onChange={() => changeMode(1)}
          />
          <label htmlFor="menu_on">
            {language === "fr" ? fr_lang.activated : en_lang.activated}
          </label>
          <input
            id="menu_off"
            name="menu_mode"
            type="radio"
            checked={nightTimeActive === 0}
            onChange={() => changeMode(0)}
          />
          <label htmlFor="menu_off">
            {language === "fr" ? fr_lang.disabled : en_lang.disabled}
          </label>
          <a href=""></a>
        </div>

        <div className="row mt-3">
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.startup : en_lang.startup} :
              </label>
              <input
                type="time"
                className="form-control"
                value={nightTimeStart}
                onChange={(e) => setNightTimeStart(e.target.value)}
              />
            </div>
          </div>
          <div className="col-md-6">
            <div className="form-group">
              <label className="text-dark">
                {language === "fr" ? fr_lang.close : en_lang.close} :
              </label>
              <input
                type="time"
                className="form-control"
                value={nightTimeStop}
                onChange={(e) => setNightTimeStop(e.target.value)}
              />
            </div>
          </div>
          <div className="col-md-12 mt-3">
            <div className="clearfix">
              <div className="float-end">
                <button
                  className="btn btn-primary"
                  onClick={() => saveNightTime()}
                >
                  <i className="fa fa-save"></i> Save
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default NightTimeScreen;
