import { useEffect, useState } from "react";
import Header from "../component/Header";
import { API_PATHS } from "../component/PathApi";
import { en_lang, fr_lang } from "../component/Languages";
function Dashbaord() {
  const [language, setLanguage] = useState(() => {
    return sessionStorage.getItem("language") || "fr";
  });
  const [datetime, setDatetime] = useState("");
  const [pH, setPH] = useState("");
  const [orp, setOrp] = useState("");
  const [temperature, setTemperature] = useState("");
  const [pump, setPump] = useState(false);
  const [pumpTwo, setPumpTwo] = useState(false);
  const [ozonePump, setOzonePump] = useState(false);
  const [lampOzone, setLampOzone] = useState(false);
  const [lampUV, setLampUV] = useState(false);
  const [heater, setHeater] = useState(false);
  const [pressure, setPressure] = useState("");
  const [flowSensor, setFlowSensor] = useState("");

  const [optionpH, setOptionpH] = useState(false);
  const [optionOrp, setOptionOrp] = useState(false);
  const [optionPressure, setOptionPressure] = useState(false);
  const [optionPumpOzone, setOptionPumpOzone] = useState(false);
  const [optionHeater, setOptionHeater] = useState(false);
  const [optionUVAmalgam, setOptionUVAmalgam] = useState(false);

  useEffect(() => {
    loadingDashboard();
    loadingMachineOption();
    const interval = setInterval(loadingDashboard, 3000);
    return () => clearInterval(interval);
  }, []);
  const loadingMachineOption = async () => {
    const response = await fetch(API_PATHS.path_machine_option);
    const result = await response.json();
    if (result.status === 200) {
      const data = result.data.machine_option[0];
      setOptionpH(parseInt(data.ph) === 1 ? true : false);
      setOptionOrp(parseInt(data.orp) === 1 ? true : false);
      setOptionPressure(parseInt(data.pressure) === 1 ? true : false);
      setOptionPumpOzone(parseInt(data.ozone_pump) === 1 ? true : false);
      setOptionHeater(parseInt(data.heater_1) === 1 ? true : false);
      setOptionUVAmalgam(parseInt(data.uv_amalgam) === 1 ? true : false);
    }
  };
  const loadingDashboard = async () => {
    const response = await fetch(API_PATHS.path_dashboard);
    const result = await response.json();

    const machine_option = await fetch(API_PATHS.path_machine_option);
    const result_machine_option = await machine_option.json();
    if (result.status === 200) {
      const now = new Date();
      const year = now.getFullYear(); // 2025
      const month = now.getMonth() + 1; // 10 (January is 0, November is 10)
      const dayOfMonth = now.getDate();
      const hours = now.getHours(); // 9
      const minutes = now.getMinutes(); // 13
      const seconds = now.getSeconds(); // 0
      const txt_time =
        dayOfMonth +
        "-" +
        month +
        "-" +
        year +
        " " +
        hours +
        ":" +
        minutes +
        ":" +
        seconds;
      setDatetime(txt_time);

      const data = result.data;
      setPH(data.ph);
      setOrp(data.orp);
      setTemperature(data.temperature);
      setPressure(data.pressure);
      var parseFlow = parseFloat(data.flow_sensor).toFixed(2);
      setFlowSensor(parseFlow);

      const split_in_dc = data.plc_in_dc.split(",");
      const split_all_out = data.plc_out.split(",");

      const data_machine_option = result_machine_option.data.machine_option[0];
      if (parseInt(data_machine_option.pool) === 1) {
        setPump(checkStatusMode(removeStingArr(split_all_out[0])));
      } else {
        setPump(checkStatusMode(removeStingArr(split_all_out[1])));
      }
      // pump 2
      if (parseInt(data_machine_option.pump) === 1) {
        setPumpTwo(checkStatusMode(removeStingArr(split_all_out[2])));
      }

      setOzonePump(checkStatusMode(removeStingArr(split_all_out[2])));
      setLampOzone(checkStatusMode(removeStingArr(split_in_dc[0])));
      setLampUV(checkStatusMode(removeStingArr(split_in_dc[1])));
      setHeater(checkStatusMode(removeStingArr(split_in_dc[2])));
    }
  };
  const removeStingArr = (value) => {
    return value.replace("[", "").replace("]", "").trim();
  };
  const checkStatusMode = (status) => {
    if (status.trim() === "True") {
      return true;
    } else if (status.trim() === "False") {
      return false;
    }
  };

  return (
    <div className="container-fluid">
      <Header name={"Accueil"} />
      <div className="row mt-3">
        <div className="col-6">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">
              {language === "fr" ? fr_lang.dashboard : en_lang.dashboard}
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr" ? fr_lang.date_time : en_lang.date_time} :
              </div>
              <div className="text-dark font-size-small">{datetime}</div>
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div
                className={`${optionPressure ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {language === "fr" ? fr_lang.pressure : en_lang.pressure} :
              </div>
              <div
                className={`${optionPressure ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {pressure}
              </div>
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div className={`text-dark font-size-small`}>FlowSensor :</div>
              <div className={`text-dark font-size-small`}>{flowSensor}</div>
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr" ? fr_lang.temperature : en_lang.temperature}:
              </div>
              <div className="text-dark font-size-small">{temperature}</div>
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div
                className={`${optionpH ? "text-dark" : "text-secondary"} font-size-small`}
              >
                pH :
              </div>
              <div
                className={`${optionpH ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {pH}
              </div>
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div
                className={`${optionOrp ? "text-dark" : "text-secondary"} font-size-small`}
              >
                ORP :
              </div>
              <div
                className={`${optionOrp ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {orp}
              </div>
            </div>
          </div>
        </div>
        <div className="col-6">
          <div className="box-glass p-2 h-100">
            <div className="box-container-header ">
              {language === "fr" ? fr_lang.status : en_lang.status}
            </div>
            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr"
                  ? fr_lang.pump_filtration
                  : en_lang.pump_filtration}{" "}
                #1 :
              </div>
              <div className="text-dark font-size-small">
                <div
                  className={`${pump ? "dos-success" : "dos-danger"} `}
                ></div>
              </div>
            </div>

            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr"
                  ? fr_lang.pump_filtration
                  : en_lang.pump_filtration}{" "}
                #2:
              </div>
              <div className="text-dark font-size-small">
                <div
                  className={`${pumpTwo ? "dos-success" : "dos-danger"} `}
                ></div>
              </div>
            </div>

            <div className="d-flex justify-content-between mt-3">
              <div
                className={`${optionPumpOzone ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {language === "fr" ? fr_lang.pump_ozone : en_lang.pump_ozone} :
              </div>
              <div
                className={`${optionPumpOzone ? "text-dark" : "d-none"} font-size-small`}
              >
                <div
                  className={`${ozonePump ? "dos-success" : "dos-danger"}`}
                ></div>
              </div>
            </div>
            {/* ozone lamp */}
            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr" ? fr_lang.uv_lamp : en_lang.uv_lamp} 1 :
              </div>
              <div className="text-dark font-size-small">
                <div
                  className={`${lampOzone ? "dos-success" : "dos-danger"}`}
                ></div>
              </div>
            </div>
            {/* UV lamp */}
            <div className="d-flex justify-content-between mt-3">
              <div className="text-dark font-size-small">
                {language === "fr" ? fr_lang.uv_lamp : en_lang.uv_lamp} 2 :
              </div>
              <div className="text-dark font-size-small">
                <div
                  className={`${lampUV ? "dos-success" : "dos-danger"}`}
                ></div>
              </div>
            </div>
            <div
              className={`${optionUVAmalgam ? "" : "d-none"} d-flex justify-content-between mt-3`}
            >
              <div className={` font-size-small`}>UV Lampe 3 :</div>
              <div className={`font-size-small`}>
                <div
                  className={`${heater ? "dos-success" : "dos-danger"}`}
                ></div>
              </div>
            </div>
            <div
              className={`${optionUVAmalgam ? "d-none" : ""} d-flex justify-content-between mt-3`}
            >
              <div
                className={`${optionHeater ? "text-dark" : "text-secondary"} font-size-small`}
              >
                {language === "fr" ? fr_lang.heater : en_lang.heater} :
              </div>
              <div
                className={`${optionHeater ? "text-dark" : "d-none"} font-size-small`}
              >
                <div
                  className={`${heater ? "dos-success" : "dos-danger"}`}
                ></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Dashbaord;
